/**
* @type   : function
* @access : public
* @desc   : 컨테이너번호 유효성 체크.<br>
* <pre>사용예 :
*
* 1. $c.gus.cf_CheckCntrNo( 'CAXU2520345' );
* </pre>
* @sig    :
* @param  : 컨테이너번호
* @author : 최수빈
*/
scwin.f_checkCntrNo = function (parCntrNo) {
    var tempData = '1012131415161718192021232425262728293031323435363738';
    var cntrNo = parCntrNo.trim();

    if (cntrNo == '' || cntrNo.length != 11) {
        //$c.gus.cfAlertMsg(MSG_CM_ERR_038, ['컨테이너']); //유효한 @가 아닙니다
        return false;
    } else {
        var re = /[A-Z]{4}[0-9]{7}/;

        if (!re.test(cntrNo)) {
            //$c.gus.cfAlertMsg(MSG_CM_ERR_038, ['컨테이너']); //유효한 @가 아닙니다
            return false;
        }

        var tempPos1 = tempData.substring((cntrNo.charCodeAt(0) - 65) * 2, (cntrNo.charCodeAt(0) - 65) * 2 + 2) * 1;
        var tempPos2 = tempData.substring((cntrNo.charCodeAt(1) - 65) * 2, (cntrNo.charCodeAt(1) - 65) * 2 + 2) * 2;
        var tempPos3 = tempData.substring((cntrNo.charCodeAt(2) - 65) * 2, (cntrNo.charCodeAt(2) - 65) * 2 + 2) * 4;
        var tempPos4 = tempData.substring((cntrNo.charCodeAt(3) - 65) * 2, (cntrNo.charCodeAt(3) - 65) * 2 + 2) * 8;

        var tempSum = tempPos1 + tempPos2 + tempPos3 + tempPos4
            + (cntrNo.substring(4, 5) * 16)
            + (cntrNo.substring(5, 6) * 32)
            + (cntrNo.substring(6, 7) * 64)
            + (cntrNo.substring(7, 8) * 128)
            + (cntrNo.substring(8, 9) * 256)
            + (cntrNo.substring(9, 10) * 512);

        var tempMod = (tempSum % 11) + '';
        if (cntrNo.substring(10, 11) != tempMod.charAt(tempMod.length - 1)) {
            // $c.gus.cfAlertMsg(MSG_CM_ERR_038, ['컨테이너']); //유효한 @가 아닙니다
            return false;
        }
    }
    return true;
}

//---------------------------------------------------------
// 화면로딩시
//---------------------------------------------------------
scwin.f_OnLoad = function () {
    scwin.f_initSetTab(); //tab세팅
    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.f_ContainerTypeLoading(); // Container Type 정보
    scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리
    // scwin.f_header();
    scwin.f_ContainerTypeLoading_freight(); // Container Type 정보
    scwin.f_CurrencyLoading_freight();

    const codeOptions = [
        { grpCd: 'IL005', compID: 'lc_hhincoterm' },
    ];
    $c.data.setCommonCode(codeOptions);
}

//필요엾음
scwin.f_header = function () {

    scwin.f_Set('INIT');
    cnd_ed_hhblno.focus();
}

//---------------------------------------------------------
// Parameter Setting
// 다른 화면에서 들어올때 각 화면별 조건을 받아서 조회한다.
//---------------------------------------------------------
scwin.f_getParametrSetting = function (gubun) {
    switch (gubun) {
        case '0':
            break;

        case '1':  // Booking에서 Search Grid
            scwin.mhnoFlag = '1';
            if (scwin.v_blno == 'null') {
                cnd_ed_hhblno.setValue('');
                cnd_ed_hhblno.focus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd || "DBEX";
            cnd_ed_hhblno.setValue(scwin.v_blno);
            if (ds_hmhno.getRowCount() == '0') {
                ds_hmhno.insertRow(0);
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, 'code', scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, 'name', scwin.v_mhno);
            cnd_lc_mhno.focus();
            break;

        case '2':  // House Search
            scwin.mhnoFlag = '1';
            if (scwin.v_blno == 'null') {
                cnd_ed_hhblno.setValue('');
                cnd_ed_hhblno.focus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd || "DBEX";
            cnd_ed_hhblno.setValue(scwin.v_blno);
            if (ds_hmhno.getRowCount() == '0') {
                ds_hmhno.insertRow(0);
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, 'code', scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition() || 0, 'name', scwin.v_mhno);
            cnd_lc_mhno.focus();
            break;

        case '4': 	// Booking 에서 h b/l버튼 (create)
            scwin.f_Create();
            ed_hhbkgno.setValue(v_bkno);
            cnd_ed_hhblno.focus(); //mhno를 보여주기위해서.
            tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_hhbkgno.focus(); // 값 넣어주기 위해.
            ed_hhetd.focus(); // etd값 반영.
            lc_hhbkgseq.focus();

            //2020.03.02 국제영업3팀 개선사항 : 부킹에 등록된 ITEM 없을 경우 자동으로 30000000 (일반화물) 으로 기입 처리
            // 				if (scwin.ed_hhitem.getValue() == '') {
            if (txt_hhmitem1.getValue() == '') {//부킹정보에 아이템 코드없이 아이템 명으로 등록 된 경우가 있으므로 코드값이 아닌 명으로 체크
                ed_hhitem.setValue('30000000');
                scwin.f_OpenCommonPopUp('Item', 'T', 'F', 'F');
            }

            txt_blpic.setValue('');
            //기본으로 등록자 ID 기입 처리
            if (ed_blpic.getValue() == '') {
                ed_blpic.setValue(scwin.vUserId);
                scwin.f_PopUp('B/L PIC', 'T');
            }
            break;
    }
}

//---------------------------------------------------------
// Object Check
//---------------------------------------------------------
scwin.f_Check = function () {
    if (scwin.statusFlag == 'I') {  // 초기화시.
        cnd_lc_autono.setSelectedIndex(1);
        cnd_lc_mhno.setSelectedIndex(0);
        lc_hhbltype.setSelectedIndex(0);
        lc_hhpcgb.setSelectedIndex(0);
        lc_hhisunm.setSelectedIndex(1);
        lc_hhstype.setSelectedIndex(0);
        lc_hhcoload.setSelectedIndex(0);

        ed_hhcnt1type.setValue('22GP');
        ed_hhcnt2type.setValue('42GP');
        ed_hhcnt3type.setValue('42RE');
        ed_hhcnt4type.setValue('45GP');
        ed_hhobl.setValue('3');

        chb_hhtriange.checkAll(false);
        chb_hhnomi.checkAll(false);
        chb_hhp1.checkAll(true);
        chb_hhp2.checkAll(false);
        chb_hhp3.checkAll(false);
        chb_hhp4.checkAll(true);
        chb_hhp5.checkAll(false);
        chb_hhp6.checkAll(true);

        rd_hhdanggb.setValue('N');
        scwin.rd_hhmnfgb = 'E';

        ta_hhs.setValue('');
        ta_hhc.setValue('');
        ta_hhn.setValue('');

        txa_agentAdress.setValue('');
        ed_hhmt.setValue('');

        // 	    	booking
        chb_iptYn_booking.checkAll(false);
        // 	    	booking
    } else if (scwin.statusFlag == 'C') { // create시
        cnd_lc_autono.setSelectedIndex(1);
        cnd_lc_mhno.setSelectedIndex(0);
        lc_hhbltype.setSelectedIndex(0);
        lc_hhpcgb.setSelectedIndex(0);
        lc_hhisunm.setSelectedIndex(1);
        lc_hhstype.setSelectedIndex(0);
        lc_hhcoload.setSelectedIndex(0);

        ed_hhcnt1type.setValue('22GP');
        ed_hhcnt2type.setValue('42GP');
        ed_hhcnt3type.setValue('42RE');
        ed_hhcnt4type.setValue('45GP');
        ed_hhobl.setValue('3');

        chb_hhtriange.checkAll(false);
        chb_hhnomi.checkAll(false);
        chb_hhp1.checkAll(true);
        chb_hhp2.checkAll(false);
        chb_hhp3.checkAll(false);
        chb_hhp4.checkAll(true);
        chb_hhp5.checkAll(false);
        chb_hhp6.checkAll(true);

        rd_hhdanggb.setValue('N');
        scwin.rd_hhmnfgb = 'E';

        ta_hhs.setValue('');
        ta_hhc.setValue('');
        ta_hhn.setValue('');

        txa_agentAdress.setValue('');
        ed_hhmt.setValue('');

        chb_iptYn_booking.checkAll(false);

        if (lc_hhbltype.getValue() != 'B') {
            $c.gus.cfDisableObjects([ed_hhmt]);//cargo type bulk일때만 M/T칸 활성화
        } else {
            $c.gus.cfEnableObjects([ed_hhmt]);
            $c.gus.cfDisableObjects([lc_hhbltype]);//처음 생성한 cargo type bulk일때는 cargo type 변경 못하게
        }
    }
}

//-------------------------------------------------------------------------
// 초기화
// B/L전화면은 조회조건은 항상 HEADER를 ADDROW상태로 ON LOAD되어있음.
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    scwin.f_Set('INIT');
    cnd_ed_hhblno.focus();
}

//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
    $c.gus.cfEnableObjects([tac_tabMain.tr_tab_center0, tac_tabMain.tr_tab_center1, tac_tabMain.tr_tab_center2]);
    tac_tabMain.setSelectedTabIndex(0);
}

//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
    tac_tabMain.setSelectedTabIndex(idx);

    if (idx == 0) {
        //buttonTable.style.top  = 548 + 'px';
        buttonTable1.visible(true);
        buttonTable1.visible(true);
    } else if (idx == 1) {
        buttonTable1.visible(true);
        buttonTable1.visible(true);
    } else {
        buttonTable1.visible(false);
        buttonTable1.visible(false);
    }
}

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {
        case 'INIT': //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Copy2, btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_FileDownload, btn_HNoChg, grpBtn1, grpBtn2 // , grpBtn3, grpBtn4, grpBtn5
                , btn_1, /* ASIS 아이디 중복 :: btn_2_freight1, btn_2_freight2, btn_2_freight3,*/ /* ASIS 아이디 중복 :: pu_ResultdateChange1, pu_ResultdateChange2, pu_ResultdateChange3 */ btn_2, btn_4, btn_5_freight, btn_6_freight, btn_8
                , btn_CntrReceive, pu_departmentChange
            ]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_9_freight, btn_retrieve, btn_Clear]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObjects([cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno]); // 조회조건.
            cnd_lc_autono.setValue('');
            scwin.statusFlag = 'I';
            break;

        case 'RETRIEVE':  //조회모드

            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_CntrReceive, grpBtn1, btn_AddCntr1, btn_AddCntr2, grpBtn1, grpBtn2
                // ,grpBtn3, grpBtn4, grpBtn5
            ]);
            $c.gus.cfEnableBtnOnly([btn_Copy, btn_Copy2, btn_Create, btn_Delete, btn_FileDownload, btn_retrieve, btn_Clear
                , btn_4, btn_5_freight, btn_6_freight, btn_8, btn_9_freight, btn_10, pu_departmentChange, btn_HNoChg]);

            // 그리드 수정 못하게 한다. (Editable -> setReadOnly 치환)
            gr_ocContList.setReadOnly('grid', true);
            gr_ocElList.setReadOnly('grid', true);
            gr_selling_freight.setReadOnly('grid', true);
            gr_partner_freight.setReadOnly('grid', true);
            gr_buying_freight.setReadOnly('grid', true);

            if (scwin.statusFlag == 'C') {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            $c.gus.cfEnableObjects([cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno]); // 조회조건.

            scwin.statusFlag = '';     // flag null
            //Direct BL 생성시 Master BL 자동으로 생성되는 기능 때문에 Direct BL을 바꾸거나, Direct BL로 변경 불가능하도록 수정
            if (cnd_lc_autono.getValue() == 'DIRECT') {
                $c.gus.cfDisableObjects([cnd_lc_autono]);
            } else {
                ds_autono.deleteRow(2);
                //cnd_lc_autono.DeleteData(2);
            }
            break;

        case 'CREATE': //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Copy2, btn_Create, btn_HNoChg, btn_retrieve, btn_Clear,
                btn_Delete, btn_4, btn_5_freight, btn_6_freight, btn_8, pu_departmentChange // btn_10, 
            ]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel,
                , btn_1, btn_2_freight1, btn_2_freight2, /* ASIS 아이디 중복 :: pu_ResultdateChange1, pu_ResultdateChange2, pu_ResultdateChange3 */, btn_2, btn_9_freight, btn_Update, btn_FileDownload
                , btn_CntrReceive, grpBtn1, grpBtn2, grpBtn3, grpBtn4, grpBtn5]);
            // 그리드 수정 가능 (Editable -> setReadOnly 치환)
            gr_ocContList.setReadOnly('grid', false);
            gr_ocElList.setReadOnly('grid', false);
            gr_selling_freight.setReadOnly('grid', false);
            gr_partner_freight.setReadOnly('grid', false);
            gr_buying_freight.setReadOnly('grid', false);
            $c.gus.cfDisableObjects([ed_hhmt, ed_agent]); // 조회조건.
            $c.gus.cfDisableObjects([cnd_lc_mhno, cnd_ed_hhmblno]); // 조회조건.
            $c.gus.cfEnableObjects([cnd_ed_hhblno, cnd_lc_autono]); // 조회조건.
            ds_autono.insertRow(2);
            ds_autono.setCellAllData(2, 'code', 'DIRECT');
            ds_autono.setCellAllData(2, 'name', 'Direct');

            //cnd_lc_autono.ResetData();
            scwin.statusFlag = 'C';
            break;

        case 'UPDATE':
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Copy2, btn_Update, btn_Create, btn_Delete, btn_4, btn_retrieve, btn_Clear
                , btn_5_freight, btn_6_freight, btn_8, btn_HNoChg, pu_departmentChange]); // btn_10,
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_FileDownload, grpBtn1, grpBtn2, grpBtn3, grpBtn4, grpBtn5
                , btn_1, /* ASIS 아이디 중복 :: btn_2_freight1, btn_2_freight2, btn_2_freight3,*/ btn_2, btn_9_freight, /* ASIS 아이디 중복 :: pu_ResultdateChange1, pu_ResultdateChange2, pu_ResultdateChange3 */
                , btn_CntrReceive]);

            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();

            // 그리드 수정 가능 (Editable -> setReadOnly 치환)
            gr_ocContList.setReadOnly('grid', false);
            gr_ocElList.setReadOnly('grid', false);
            gr_selling_freight.setReadOnly('grid', false);
            gr_partner_freight.setReadOnly('grid', false);
            gr_buying_freight.setReadOnly('grid', false);

            $c.gus.cfDisableObjects([cnd_ed_hhblno, cnd_lc_autono, cnd_lc_mhno, cnd_ed_hhmblno]); // 조회조건.
            scwin.statusFlag = 'U';
            break;

        case 'SAVE':
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_FileDownload, btn_HNoChg]);
            scwin.f_Set('RETRIEVE');
            break;
    }
}

//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다.
//-------------------------------------------------------------------------
