scwin.f_Cancel = function () {
    //cmd anable
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno, true);

    cnd_ed_hhblno.focus();

    if (scwin.statusFlag == 'C') {
        scwin.f_Set('INIT');
    } else {
        scwin.f_Set('RETRIEVE');
        $c.data.undoRow(ds_houseblList, 'Y');
        $c.data.undoRow(ds_partnerInfo, 'Y');
        scwin.f_cancelRow(1);
        scwin.f_cancelRow(2);
    }

    scwin.f_Cancel_freight();
    scwin.f_Cancel_booking();
}

