scwin.f_addRow1 = function () {
    scwin.f_addRow(1);
}

scwin.f_addRow2 = function () {
    scwin.f_addRow(2);
}

scwin.f_addRow = async function (disGubun) {
    switch (disGubun) {
        case 1:  	// Container
            if (cnd_ed_hhblno.getValue() == '') {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
            } else {
                idx = ds_ocContList.insertRow();
                ds_ocContList.setCellData(idx, 'kcomcd', scwin.hd_kcomcd);
                ds_ocContList.setCellData(idx, 'mchblno', cnd_ed_hhblno.getValue());  //update일때.
                ds_ocContList.setCellData(idx, 'mhno', cnd_lc_mhno.getValue());  //update일때.
                ds_ocContList.setCellData(idx, 'inpid', scwin.vUserId);
                ds_ocContList.setCellData(idx, 'mcpart', 'N');
                ds_ocContList.setCellData(idx, 'mcpkg', '0');
                ds_ocContList.setCellData(idx, 'mcwgt', '0');
                ds_ocContList.setCellData(idx, 'mcmsr', '0');
                // gr_ocContList.focus();
            }
            break;

        case 2:  	// El
            if (cnd_ed_hhblno.getValue() == '') {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
            } else {
                idx = ds_ocElList.insertRow();
                ds_ocElList.setCellData(idx, 'kcomcd', scwin.hd_kcomcd);
                ds_ocElList.setCellData(idx, 'hhblno', cnd_ed_hhblno.getValue());  //update일때.
                ds_ocElList.setCellData(idx, 'mhno', cnd_lc_mhno.getValue());  //update일때.
                ds_ocElList.setCellData(idx, 'inpid', scwin.vUserId);
                ds_ocElList.setCellData(idx, 'pgb', 'N');

                ds_ocElList.setCellData(idx, 'pkg', ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhpkg') || 0);
                ds_ocElList.setCellData(idx, 'unit', ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhunitcd'));
                ds_ocElList.setCellData(idx, 'wgt', ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhgwgt') || 0);

                // gr_ocElList.focus();
            }
            break;
        default:
            break;
    }
}

//---------------------------------------------------------
// 행삭제
//---------------------------------------------------------
scwin.f_deleteRow1 = function () {
    scwin.f_deleteRow(1);
}
scwin.f_deleteRow2 = function () {
    scwin.f_deleteRow(2);
}
scwin.f_deleteRow = function (disGubun) {
    switch (disGubun) {
        case 1:  	// Container
            if (ds_ocContList.getRowStatus(ds_ocContList.getRowPosition()) == 'C') {
                ds_ocContList.removeRow(ds_ocContList.getRowPosition());
            } else {
                ds_ocContList.deleteRow(ds_ocContList.getRowPosition());
            }
            break;

        case 2:  	// El
            if (ds_ocElList.getRowStatus(ds_ocElList.getRowPosition()) == 'C') {
                ds_ocElList.removeRow(ds_ocElList.getRowPosition());
            } else {
                ds_ocElList.deleteRow(ds_ocElList.getRowPosition());
            }
            break;

        default:
            break;
    }
}
//---------------------------------------------------------
// 행취소
//---------------------------------------------------------
scwin.f_cancelRow1 = function () {
    scwin.f_cancelRow(1);
}

scwin.f_cancelRow2 = function () {
    scwin.f_cancelRow(2);
}

scwin.f_cancelRow = function (disGubun) {
    switch (disGubun) {
        case 1: // Container
            for (var i = ds_ocContList.getTotalRow() - 1; i >= 0; i--) {
                if (ds_ocContList.getRowStatus(i) == 'C') {
                    ds_ocContList.removeRow(i);
                } else {
                    ds_ocContList.undoRow(i);
                }
            }
            break;

        case 2: // El
            for (var i = ds_ocElList.getTotalRow() - 1; i >= 0; i--) {
                if (ds_ocElList.getRowStatus(i) == 'C') {
                    ds_ocElList.removeRow(i);
                } else {
                    ds_ocElList.undoRow(i);
                }
            }
            break;

        default:
            break;
    }
}

//---------------------------------------------------------
// function name : f_validate
// function desc :
//---------------------------------------------------------
scwin.f_validate = async function () {

    // VALIDATE
    if (!$c.gus.cfValidate([ed_hhetd, ed_hhondt, ed_hheta, ed_hhisudt, ed_creadyDt])) {  //validExp 가 yes일때 check
        return false;
    }

    if (ed_hhetd.getValue() == '') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['ETD']); //@는 필수입력항목입니다.
        // 	    	tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        scwin.f_selectTabMenu(0);
        ed_hhetd.focus();
        return false;
    }

    //22.04.25 Result Date 필수값으로 설정
    if (ed_creadyDt.getValue() == '') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Result Date']); //@는 필수입력항목입니다.
        scwin.f_selectTabMenu(0);
        ed_creadyDt.focus();
        return false;
    }

    // 날짜 범위 확인
    if (ed_hheta.getValue() != '') {
        if (!$c.gus.cfIsAfterDate(ed_hhetd.getValue(), ed_hheta.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_048, new Array('ETD', 'ETA'));  //@은(는) 보다 작아야 합니다.
            // 				tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            scwin.f_selectTabMenu(0);
            ed_hhetd.focus();
            return false;
        }
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hhetd.getValue().toDate()) > 3) {
        await $c.win.alert('ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.');
        tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhetd.focus();
        return false;
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hheta.getValue().toDate()) > 3) {
        await $c.win.alert('ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.');
        tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hheta.focus();
        return false;
    }


    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if ($c.gus.cfYearsBetween(ed_hhetd.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
        await $c.win.alert('ETD가 3년 이상의 과거 일 수 없습니다.');
        tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhetd.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if ($c.gus.cfYearsBetween(ed_hheta.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
        await $c.win.alert('ETA가 3년 이상의 과거 일 수 없습니다.');
        tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hheta.focus();
        return false;
    }


    //ETA-ETD(transit time)가 150일을 초과할 수 없다.  *150일(총 운항DATE 수) : ETA날짜에서 ETD날짜를 빼고 +1 한 날짜
    if (WebSquare.date.dateDiff(ed_hhetd.getValue(), ed_hheta.getValue()) > 149) {
        await $c.win.alert('ETA-ETD(transit time)가 150일을 초과할 수 없습니다.');
        tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhetd.focus();
        return false;
    }


    if (ed_hhactcust.getValue() == '' || ed_hhactcust.getValue() == '999908') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer']); //@는 필수입력항목입니다.
        // 	    	tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        scwin.f_selectTabMenu(0);
        ed_hhactcust.focus();
        return false;
    }

    if (ed_hhbuyer.getValue() == '') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Department']); //@는 필수입력항목입니다.
        // 	    	tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        scwin.f_selectTabMenu(0);
        ed_hhbuyer.focus();
        return false;
    }

    if (txt_hhmitem2.getValue() == '') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['EDI Item']); //@는 필수입력항목입니다.
        //             $c.gus.cfViewTab(1);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        scwin.f_selectTabMenu(1);
        txt_hhmitem2.focus();
        return false;
    }

    // 신규시 DBEX가 아닌 DBEXxxxxx로 생성 못함.
    if (scwin.statusFlag == 'C') {
        if (cnd_ed_hhblno.getValue().length != 4 && cnd_ed_hhblno.getValue().substr(0, 4) == 'DBEX') {
            //$c.gus.cfAlertMsg(MSG_CM_ERR_026, ['Auto Create','DBEX']);   // @은(는) '@' 형식이어야 합니다.
            //cnd_ed_hhblno.focus();
            //return false;
        }
    }

    //CommCode 처리
    //ds_customerInfo.DataID = '/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveCustomerInfo&param1=' + ed_hhactcust.getValue().trim();
    //ds_customerInfo.Reset();
    scwin.f_commCode(ds_customerInfo, 'ilCommonEBC', 'retriveCustomerInfo', ed_hhactcust.getValue().trim());

    if (ds_customerInfo.getRowCount() > 0) {
        if (ed_hhbuyer.getValue() != ds_customerInfo.getCellData(ds_customerInfo.getRowPosition() || 0, 'col1')) {
            await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_007);
            tac_tabMain.setSelectedTabIndex(0);
            ed_hhbuyer.focus();
            return false;
        }
    }

    // Container Type dual check
    if (!scwin.f_containerDualCheck()) return false;

    // Container Type value check
    if (ed_hhcnt1type.getValue() != '') {
        var STR = ds_containerType.getCellData(0, ed_hhcnt1type.getValue());
        if (STR == '0') {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']); //  @이(가) 존재하지 않습니다.
            // 		    	 tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            scwin.f_selectTabMenu(0);
            ed_hhcnt1type.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_hhcnt2type.getValue() != '') {
        var STR = ds_containerType.getCellData(0, ed_hhcnt2type.getValue());
        if (STR == '0') {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']); //  @이(가) 존재하지 않습니다.
            // 		    	 tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            scwin.f_selectTabMenu(0);
            ed_hhcnt2type.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_hhcnt3type.getValue() != '') {
        var STR = ds_containerType.getCellData(0, ed_hhcnt3type.getValue());
        if (STR == '0') {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']); //  @이(가) 존재하지 않습니다.
            // 		    	 tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            scwin.f_selectTabMenu(0);
            ed_hhcnt3type.focus();
            return false;
        }
    }

    // Container Type value check
    if (ed_hhcnt4type.getValue() != '') {
        var STR = ds_containerType.getCellData(0, ed_hhcnt4type.getValue());
        if (STR == '0') {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']); //  @이(가) 존재하지 않습니다.
            // 		    	 tac_tabMain.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            scwin.f_selectTabMenu(0);
            ed_hhcnt4type.focus();
            return false;
        }
    }

    // Container
    var checked = 0;
    for (var i = 0; i < ds_ocContList.getRowCount(); i++) {
        if (ds_ocContList.getCellData(i, 'mccntno') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Container']); //@는 필수입력항목입니다.
            gr_ocContList.focus();
            return false;
        }
        checked++;
    }

    // Container Type
    var checked = 0;
    for (var i = 0; i < ds_ocContList.getRowCount(); i++) {
        if (ds_ocContList.getCellData(i, 'mctype') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Container Type']); //@는 필수입력항목입니다.
            gr_ocContList.focus();
            return false;
        }
        checked++;
    }

    // 수출신고번호
    var checked = 0;
    v_elno = '';
    for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, 'elno') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['수출신고번호']); //@는 필수입력항목입니다.
            gr_ocElList.focus();
            return false;
        }
        checked++;
    }

    // unit
    var checked = 0;
    for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, 'unit') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Unit']); //@는 필수입력항목입니다.
            gr_ocElList.focus();
            return false;
        }
        checked++;
    }

    // Package
    var checked = 0;
    for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, 'pkg') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Package']); //@는 필수입력항목입니다.
            gr_ocElList.focus();
            return false;
        }
        checked++;
    }
    // Weight
    var checked = 0;
    for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, 'wgt') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Weight']); //@는 필수입력항목입니다.
            gr_ocElList.focus();
            return false;
        }
        checked++;
    }

    // 포장기호
    var checked = 0;
    for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, 'mgb') != '') {
            if (ds_ocElList.getCellData(i, 'mpkg') == '') {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['package']); //@는 필수입력항목입니다.
                gr_ocElList.focus();
                return false;
            }
            if (ds_ocElList.getCellData(i, 'mut') == '') {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Unit']); //@는 필수입력항목입니다.
                gr_ocElList.focus();
                return false;
            }
        }
        checked++;
    }
    // 분할
    var checked = 0;
    for (var i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, 'pgb') == 'Y') {
            if (ds_ocElList.getCellData(i, 'pseq') == '') {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['ISO']); //@는 필수입력항목입니다.
                gr_ocElList.focus();
                return false;
            }
        }
        checked++;
    }

    // Cargo Type Check
    if (lc_hhbltype.getValue() == 'B'
        && (ed_hhcnt1.getValue() != '0' || ed_hhcnt2.getValue() != '0' || ed_hhcnt3.getValue() != '0' || ed_hhcnt4.getValue() != '0')) {

        var msg = 'Cargo Type이 Bulk 이면서 Container정보가 입력되었습니다.\n입력된 정보가 맞으시면 확인처리 해 주십시오.';
        if (!(await $c.win.confirm(msg))) {
            ed_hhcnt1.focus();
            return false;
        }
    }

    //EDI ITEM 글자수 및 특수문자 여부 CHECK
    if (scwin.f_isOnlySpecial(txt_hhmitem2.getValue())) {
        await $c.win.alert('EDI ITEM에 특수문자만 입력은 불가능합니다.');
        return false;
    }

    if ($c.gus.cfGetByteLength(txt_hhmitem2.getValue()) < 2) {
        await $c.win.alert('EDI ITEM에 2글자 이상을 입력하셔야합니다.');
        return false;
    }

    if ($c.gus.cfGetByteLength(scwin.txt_addr1) >= 47 || $c.gus.cfGetByteLength(scwin.txt_addr2) >= 47 || $c.gus.cfGetByteLength(scwin.txt_addr3) >= 47
        || $c.gus.cfGetByteLength(scwin.txt_addr4) >= 47 || $c.gus.cfGetByteLength(scwin.txt_addr5) >= 47) {
        await $c.win.alert('Agent Info의 글자수가 너무 깁니다. \nBL 출력시 칸을 초과할 수 있습니다.');
        return false;
    }

    return true;
}

scwin._popTagetDs = null;
