        param4: seaAirCls,
        param5: blNo,
        param6: mhno,
        param7: '',
        param8: '',
        param9: '',
        param10: '',
        param11: '',
        param12: '',
        param13: '',
        param14: ''
    };

    ds_PostDtDataSet.removeAll();
    scwin._popTagetDs = ds_PostDtDataSet;
    dma_comCode.setJSON(params);
    await $c.sbm.execute(sbm_popup);

    return ds_PostDtDataSet;
}

