scwin.udc_hhactcust_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_hhactcust, txt_hhactcustnm);
    scwin.ed_hhactattn = "";
    scwin.txt_hhactattnnm = "";
