    if (ed_hhncd.setValue) ed_hhncd.setValue(ccd);
    else ed_hhncd.value = ccd;

    var consigneeText = (ta_hhc.getValue ? ta_hhc.getValue() : (ta_hhc.value || ta_hhc.text || ta_hhc.Text || ''));
    if (ta_hhn.setValue) ta_hhn.setValue(consigneeText);
    else ta_hhn.value = consigneeText;

    ed_hhvslcd.focus();
};


// -------------------------------------------------------------------------
// FCL Control - 숫자를 영문으로 변환하거나 포멧 처리
// -------------------------------------------------------------------------
scwin.f_cargoControl = function () {
    if (!(scwin.statusFlag == 'C' || scwin.statusFlag == 'U')) return;

    var blType = (lc_hhbltype.getValue ? lc_hhbltype.getValue() : (lc_hhbltype.BindColVal || lc_hhbltype.value || ''));
    if (blType === 'F') {
        // 초기화
        txt_hhsubpkg.value = '';
        txt_hhunit2.value = '';
        txt_hhsay.value = '';

        var result = '';
        var resultSay = '';
        var resultCnt = 0;

        // 컨테이너 타입 코드들
        var cnt1type = (ed_hhcnt1type.getValue ? ed_hhcnt1type.getValue() : (ed_hhcnt1type.value || ed_hhcnt1type.text || ed_hhcnt1type.Text || ''));
        var cnt2type = (ed_hhcnt2type.getValue ? ed_hhcnt2type.getValue() : (ed_hhcnt2type.value || ed_hhcnt2type.text || ed_hhcnt2type.Text || ''));
        var cnt3type = (ed_hhcnt3type.getValue ? ed_hhcnt3type.getValue() : (ed_hhcnt3type.value || ed_hhcnt3type.text || ed_hhcnt3type.Text || ''));
        var cnt4type = (ed_hhcnt4type.getValue ? ed_hhcnt4type.getValue() : (ed_hhcnt4type.value || ed_hhcnt4type.text || ed_hhcnt4type.Text || ''));

        // 수량
        var cnt1 = (ed_hhcnt1.getValue ? ed_hhcnt1.getValue() : (ed_hhcnt1.value || ed_hhcnt1.text || ed_hhcnt1.Text || '0'));
        var cnt2 = (ed_hhcnt2.getValue ? ed_hhcnt2.getValue() : (ed_hhcnt2.value || ed_hhcnt2.text || ed_hhcnt2.Text || '0'));
        var cnt3 = (ed_hhcnt3.getValue ? ed_hhcnt3.getValue() : (ed_hhcnt3.value || ed_hhcnt3.text || ed_hhcnt3.Text || '0'));
        var cnt4 = (ed_hhcnt4.getValue ? ed_hhcnt4.getValue() : (ed_hhcnt4.value || ed_hhcnt4.text || ed_hhcnt4.Text || '0'));

        // GAUCE: ds_containerType.getCellData(0, code)
        // WebSquare: getMatchedIndex('code', code) (없으면 -1)
        var i1 = ds_containerType.getMatchedIndex ? ds_containerType.getMatchedIndex('code', cnt1type) : -1;
        var i2 = ds_containerType.getMatchedIndex ? ds_containerType.getMatchedIndex('code', cnt2type) : -1;
        var i3 = ds_containerType.getMatchedIndex ? ds_containerType.getMatchedIndex('code', cnt3type) : -1;
        var i4 = ds_containerType.getMatchedIndex ? ds_containerType.getMatchedIndex('code', cnt4type) : -1;

        // build helper
        function appendContainer(idx, qty, isFirst, prevQtyZeroTextField) {
            if (idx < 0) return { result: '', say: '', qty: 0, appended: false };

            var q = Number(qty || 0);
            if (!q) return { result: '', say: '', qty: 0, appended: false };

            var name = ds_containerType.getCellData(idx, 'name');
            var STRC = name + ' X ' + qty;

            var eng = scwin.cf_NumChangeEng(String(qty)); // cf_ -> $c.gus.cf_
            var seg = (isFirst ? STRC : (' & ' + STRC));
            var segSay = (isFirst ? (eng + '(' + STRC + ')') : (' & ' + eng + '(' + STRC + ')'));

            return { result: seg, say: segSay, qty: q, appended: true };
        }

        var first = true;

        var a1 = appendContainer(i1, cnt1, true);
        if (a1.appended) {
            result = a1.result;
            resultSay = a1.say;
            resultCnt = a1.qty;
            first = false;
        }

        var a2 = appendContainer(i2, cnt2, first);
        if (a2.appended) {
            result = result + a2.result;
            resultSay = resultSay + a2.say;
            resultCnt = resultCnt + a2.qty;
            first = false;
        }

        var a3 = appendContainer(i3, cnt3, first);
        if (a3.appended) {
            result = result + a3.result;
            resultSay = resultSay + a3.say;
            resultCnt = resultCnt + a3.qty;
            first = false;
        }

        var a4 = appendContainer(i4, cnt4, first);
        if (a4.appended) {
            result = result + a4.result;
            resultSay = resultSay + a4.say;
            resultCnt = resultCnt + a4.qty;
        }

        txt_hhsubpkg.value = result;

        // Number of Containers or Packages2
        var pkg = (ed_hhpkg.getValue ? ed_hhpkg.getValue() : (ed_hhpkg.value || ed_hhpkg.text || ed_hhpkg.Text || '0'));
        if (pkg !== '0' && pkg !== '') {
            txt_hhunit2.value = pkg + ' ' + (txt_hhunit.value || '');
        }

        // Say
        if (Number(resultCnt) === 1) txt_hhsay.value = resultSay + ' CONTAINER ONLY';
        else txt_hhsay.value = resultSay + ' CONTAINERS ONLY';

        // Print option (체크박스)
        chb_hhp1.checkAll(true);
        chb_hhp2.checkAll(true);
        chb_hhp3.checkAll(true);

    } else if (blType === 'L') {
        txt_hhsubpkg.value = '';
        txt_hhunit2.value = '';
        txt_hhsay.value = '';

        var pkgL = (ed_hhpkg.getValue ? ed_hhpkg.getValue() : (ed_hhpkg.value || ed_hhpkg.text || ed_hhpkg.Text || '0'));
        if (pkgL !== '0' && pkgL !== '') {
            txt_hhsubpkg.value = pkgL + ' ' + (txt_hhunit.value || '');
            var engL = scwin.cf_NumChangeEng(String(pkgL));
            if (String(pkgL) == '1') txt_hhsay.value = engL + '(' + pkgL + ') ' + (txt_hhunit.value || '') + ' ONLY';
            else txt_hhsay.value = engL + '(' + pkgL + ') ' + (txt_hhunit.value || '') + 'S ONLY';
        }

        chb_hhp1.checkAll(false);
        chb_hhp2.checkAll(true);
        chb_hhp3.checkAll(false);
    }
};

// 특수문자만 있는지 체크
scwin.f_isOnlySpecial = function (str) {
    return /^[^a-zA-Z0-9]+$/.test(str);
}
