scwin.f_Save_freight = async function () {

    var dirty =
        ds_houseblList_freight.getModifiedIndex().length != 0 ||
        ds_selling_freight.getModifiedIndex().length != 0 ||
        ds_partner_freight.getModifiedIndex().length != 0 ||
        ds_buying_freight.getModifiedIndex().length != 0;

    if (dirty) {
        if (!await scwin.f_validate_freight() || !await scwin.f_FreightValidate() || !await scwin.f_JobCloseYn()) {
            return false;
        }
    }
    return true;
};

