//-------------------------------------------------------------------------
// Freight Row Add 공통 (Selling/Partner/Buying)
//-------------------------------------------------------------------------
scwin._freight_getSpec = function (disGubun) {
    // disGubun: 1 Selling, 2 Partner, 3 Buying
    if (disGubun == 1) {
        return {
            ds: ds_selling_freight,
            grid: gr_selling_freight,
            copy: {
                rateCol: 'sellUpr',
                amtFcrc: 'sellAmtFcrc',
                amtW: 'sellAmt',
                amtUsd: 'usdAmt'
            },
            fixed: {
                locPtnCls: '1',
                mblHblCls: 'H',
                seaAirCls: 'S',
                drCrCls: 'D'
            },
            // header fill
            fill: function (row) {
                var r0 = this.ds.getRowPosition();

                this.ds.setCellData(row, 'kcomcd', scwin.hd_kcomcd);
                this.ds.setCellData(row, 'blNo', cnd_ed_hhblno.getValue());
                this.ds.setCellData(row, 'mhno', cnd_lc_mhno.getValue()); // 필요시 code값이면 project 방식으로 교체
                this.ds.setCellData(row, 'odrNo', ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition(), 'odrNo'));

                this.ds.setCellData(row, 'locPtnCls', this.fixed.locPtnCls);
                this.ds.setCellData(row, 'mblHblCls', this.fixed.mblHblCls);
                this.ds.setCellData(row, 'seaAirCls', this.fixed.seaAirCls);
                this.ds.setCellData(row, 'drCrCls', this.fixed.drCrCls);

                this.ds.setCellData(row, 'ppccCls', scwin.hd_hhpcgb_freight);
                this.ds.setCellData(row, 'inpid', scwin.vUserId || ''); // JSP <%=userId%> 대체 (프로젝트 전역 userId로 바꿔)
                this.ds.setCellData(row, 'bilgClntNo', scwin.ed_hhactcust_freight);
                this.ds.setCellData(row, 'bilgClntNm', scwin.txt_hhactcustnm_freight);
                this.ds.setCellData(row, 'rsltsStdDt', ed_creadyDt.getValue());
                this.ds.setCellData(row, 'exRateTyp', lc_selling_hhexgb_freight.getValue());
            },
            after: function (row) {
                scwin.f_sellingUnitLoading_freight();
                this.ds.setCellData(row, 'fareUnit', ds_sellingUnit_freight.getCellData(0, 'code'));
                scwin.f_packageRateSellingLoading_freight(row, '');
                this.grid.focus();
                this.grid.setFocusedCell(row, 'fareEngCd');
            }
        };
    }

    if (disGubun == 2) {
        return {
            ds: ds_partner_freight,
            grid: gr_partner_freight,
            copy: {
                rateCol: 'sellUpr',
                amtFcrc: 'sellAmtFcrc',
                amtW: 'sellAmt',
                amtUsd: 'usdAmt'
            },
            fixed: {
                locPtnCls: '2',
                mblHblCls: 'H',
                seaAirCls: 'S',
                drCrCls: 'D' // 원본: drCrCls / drCrCls 혼재 -> 프로젝트 컬럼명에 맞춰 조정
            },
            fill: function (row) {
                this.ds.setCellData(row, 'kcomcd', scwin.hd_kcomcd);
                this.ds.setCellData(row, 'blNo', cnd_ed_hhblno.getValue());
                this.ds.setCellData(row, 'mhno', cnd_lc_mhno.getValue());
                this.ds.setCellData(row, 'odrNo', ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition(), 'odrNo'));

                this.ds.setCellData(row, 'drCrCls', this.fixed.drCrCls); // Partner는 drCrCls 컬럼 사용
                this.ds.setCellData(row, 'locPtnCls', this.fixed.locPtnCls);
                this.ds.setCellData(row, 'mblHblCls', this.fixed.mblHblCls);
                this.ds.setCellData(row, 'seaAirCls', this.fixed.seaAirCls);

                this.ds.setCellData(row, 'ppccCls', scwin.hd_hhpcgb_freight);
                this.ds.setCellData(row, 'inpid', scwin.vUserId || '');

                this.ds.setCellData(row, 'bilgClntNo', scwin.ed_hhagent_freight);
                this.ds.setCellData(row, 'bilgClntNm', scwin.txt_hhagentnm_freight);
                this.ds.setCellData(row, 'rsltsStdDt', ed_creadyDt.getValue());
                this.ds.setCellData(row, 'exRateTyp', lc_selling_hhexgb_freight.getValue());
            },
            after: function (row) {
                scwin.f_partnerUnitLoading_freight();
                this.ds.setCellData(row, 'fareUnit', ds_partnerUnit_freight.getCellData(0, 'code'));
                scwin.f_packageRatePartnerLoading_freight(row, '');
                this.grid.focus();
                this.grid.setFocusedCell(row, 'fareEngCd');
            }
        };
    }

    // disGubun == 3 Buying
    return {
        ds: ds_buying_freight,
        grid: gr_buying_freight,
        copy: {
            rateCol: 'pchsUpr',
            amtFcrc: 'pchsAmtFcrc',
            amtW: 'pchsAmt',
            amtUsd: 'usdAmt'
        },
        fixed: {
            locPtnCls: '1',
            mblHblCls: 'H',
            seaAirCls: 'S',
            drCrCls: 'C'
        },
        fill: function (row) {
            this.ds.setCellData(row, 'kcomcd', scwin.hd_kcomcd);
            this.ds.setCellData(row, 'blNo', cnd_ed_hhblno.getValue());
            this.ds.setCellData(row, 'mhno', cnd_lc_mhno.getValue());
            this.ds.setCellData(row, 'odrNo', ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition(), 'odrNo'));

            this.ds.setCellData(row, 'locPtnCls', this.fixed.locPtnCls);
            this.ds.setCellData(row, 'mblHblCls', this.fixed.mblHblCls);
            this.ds.setCellData(row, 'seaAirCls', this.fixed.seaAirCls);
            this.ds.setCellData(row, 'drCrCls', this.fixed.drCrCls);

            this.ds.setCellData(row, 'ppccCls', scwin.hd_hhpcgb_freight);
            this.ds.setCellData(row, 'inpid', scwin.vUserId || '');

            this.ds.setCellData(row, 'pchsClntNo', scwin.ed_hhliner_freight);
            this.ds.setCellData(row, 'pchsClntNm', scwin.txt_hhlinernm_freight);
            this.ds.setCellData(row, 'rsltsStdDt', ed_creadyDt.getValue());
            this.ds.setCellData(row, 'exRateTyp', lc_selling_hhexgb_freight.getValue());
            this.ds.setCellData(row, 'pchsTyp', '1');
        },
        after: function (row) {
            scwin.f_buyingUnitLoading_freight();
            this.ds.setCellData(row, 'fareUnit', ds_buyingUnit_freight.getCellData(0, 'code'));
            scwin.f_packageRateBuyingLoading_freight(row, '');
            this.grid.focus();
            this.grid.setFocusedCell(row, 'pchsTyp');
        }
    };
};

//-------------------------------------------------------------------------
// row 삽입(원본: addRow / insertRow) - WebSquare 버전
//  - 맨끝이면 addRow
//  - 아니면 현재row 다음에 insertRow
// 반환: 생성된 rowIndex
//-------------------------------------------------------------------------
scwin._freight_insertRow = function (ds) {
    var cnt = ds.getRowCount();
    var cur = ds.getRowPosition(); // 1-base인 경우/0-base인 경우 프로젝트에 맞춰 조정 필요

    if (cnt == 0 || cnt == cur) {
        idx = ds.insertRow();
        return ds.getRowPosition() || idx;
    } else {
        idx = ds.insertRow();
        return ds.getRowPosition() || idx;
    }
};

//-------------------------------------------------------------------------
// 직전행 값 복사(단가/환율/금액류)
//-------------------------------------------------------------------------
scwin._freight_copyPrevAmounts = function (spec, newRow) {
    var ds = spec.ds;
    var cur = ds.getRowPosition();

    var rate = ds.getCellData(cur, spec.copy.rateCol);
    var exRate = ds.getCellData(cur, 'exRate');
    var a1 = ds.getCellData(cur, spec.copy.amtFcrc);
    var a2 = ds.getCellData(cur, spec.copy.amtW);
    var a3 = ds.getCellData(cur, spec.copy.amtUsd);

    ds.setCellData(newRow, spec.copy.rateCol, rate);
    ds.setCellData(newRow, 'exRate', exRate);
    ds.setCellData(newRow, spec.copy.amtFcrc, a1);
    ds.setCellData(newRow, spec.copy.amtW, a2);
    ds.setCellData(newRow, spec.copy.amtUsd, a3);
};

//---------------------------------------------------------
// 행추가 (WebSquare)
//---------------------------------------------------------
scwin.f_addRow_freight = async function (disGubun) {

    if (cnd_ed_hhblno.getValue() == '') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }

    var spec = scwin._freight_getSpec(disGubun);
    var row = scwin._freight_insertRow(spec.ds);

    spec.fill(row);
    scwin._freight_copyPrevAmounts(spec, row);

    // unit / ratepack / focus
    spec.after(row);
};

//---------------------------------------------------------
// 다중 행추가 (WebSquare)
//---------------------------------------------------------
scwin.f_addRowMulti_freight1 = function () {
    scwin.f_addRowMulti_freight(1);
}
scwin.f_addRowMulti_freight2 = function () {
    scwin.f_addRowMulti_freight(2);
}
scwin.f_addRowMulti_freight3 = function () {
    scwin.f_addRowMulti_freight(3);
}


scwin.f_addRowMulti_freight = async function (disGubun) {

    var row = 0;
    var rowMake_selling = ed_rowMake_selling.getValue() == '' ? 1 : parseInt(ed_rowMake_selling.getValue().trim());
    var rowMake_partner = ed_rowMake_partner.getValue() == '' ? 1 : parseInt(ed_rowMake_partner.getValue().trim());
    var rowMake_buying = ed_rowMake_buying.getValue() == '' ? 1 : parseInt(ed_rowMake_buying.getValue().trim());


    switch (disGubun) {
        case 1:  	//Selling
            if (cnd_ed_hhblno.getValue() == '') {
                $c.gus.cfAlertMsg('No data found./Could not find any relevant data.'); //  해당되는 자료가 존재하지 않습니다
            } else {

                for (var i = 0; i < rowMake_selling; i++) {
                    if (ds_selling_freight.getTotalRow() == 0 || ds_selling_freight.getTotalRow() == ds_selling_freight.getRowPosition()) {
                        idx = ds_selling_freight.insertRow();
                        row = idx;
                    } else {
                        idx = ds_selling_freight.insertRow(ds_selling_freight.getRowPosition() + 1);
                        row = idx;
                    }

                    var g_Rate = ds_selling_freight.getCellData(idx - 1, 'sellUpr') || 0;
                    var g_Ex_Rate = ds_selling_freight.getCellData(idx - 1, 'exRate') || 0;

                    var g_Amount = ds_selling_freight.getCellData(idx - 1, 'sellAmtFcrc') || 0;
                    var g_Amount_W = ds_selling_freight.getCellData(idx - 1, 'sellAmt') || 0;
                    var g_Amount_US = ds_selling_freight.getCellData(idx - 1, 'usdAmt') || 0;

                    ds_selling_freight.setCellData(row, 'kcomcd', scwin.hd_kcomcd);
                    ds_selling_freight.setCellData(row, 'blNo', cnd_ed_hhblno.getValue());             //update일때.
                    ds_selling_freight.setCellData(row, 'mhno', cnd_lc_mhno.getValue()); //update일때.
                    ds_selling_freight.setCellData(row, 'odrNo', ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition() || 0, 'odrNo'));
                    ds_selling_freight.setCellData(row, 'locPtnCls', '1');                       //국내 : 1, 해외 :2 
                    ds_selling_freight.setCellData(row, 'mblHblCls', 'H');                       //house/master		
                    ds_selling_freight.setCellData(row, 'seaAirCls', 'S');                       // sea/air
                    ds_selling_freight.setCellData(row, 'drCrCls', 'D');                         // DR/CR		
                    ds_selling_freight.setCellData(row, 'ppccCls', ds_houseblList_freight.getCellData(0, 'hhpcgb'));  	       //pp/cc											
                    ds_selling_freight.setCellData(row, 'inpid', scwin.vUserId);

                    ds_selling_freight.setCellData(row, 'bilgClntNo', ed_hhactcust_freight.getValue());       //CUSTOMER	
                    ds_selling_freight.setCellData(row, 'bilgClntNm', txt_hhactcustnm_freight.getValue());   //CUSTOMER name										
                    ds_selling_freight.setCellData(row, 'rsltsStdDt', ed_creadyDt.getValue());       //실적일	 
                    ds_selling_freight.setCellData(row, 'exRateTyp', lc_selling_hhexgb_freight.getValue());     //exgb		

                    ds_selling_freight.setCellData(row, 'sellUpr', g_Rate);
                    ds_selling_freight.setCellData(row, 'exRate', g_Ex_Rate);

                    ds_selling_freight.setCellData(row, 'sellAmtFcrc', g_Amount);
                    ds_selling_freight.setCellData(row, 'sellAmt', g_Amount_W);
                    ds_selling_freight.setCellData(row, 'usdAmt', g_Amount_US);
                    scwin.f_sellingVat_freight(row);

                    //unit처리.
                    scwin.f_sellingUnitLoading_freight();
                    ds_selling_freight.setCellData(row, 'fareUnit', ds_sellingUnit_freight.getCellData(0, 'code'));
                    scwin.f_packageRateSellingLoading_freight(row, '');

                    // gr_selling_freight.Focus();
                }
            }
            break;

        case 2:  	// Partner

            if (cnd_ed_hhblno.getValue() == '') {
                $c.gus.cfAlertMsg('No data found./Could not find any relevant data.'); //  해당되는 자료가 존재하지 않습니다
            } else {
                for (var i = 0; i < rowMake_partner; i++) {
                    if (ds_partner_freight.getTotalRow() == 0 || ds_partner_freight.getTotalRow() == ds_partner_freight.getRowPosition()) {
                        idx = ds_partner_freight.insertRow();
                        row = idx;
                    } else {
                        idx = ds_partner_freight.insertRow(ds_partner_freight.getRowPosition() + 1);
                        row = idx;
                    }

                    var g_Rate = ds_partner_freight.getCellData(idx - 1, 'sellUpr') || 0;
                    var g_Ex_Rate = ds_partner_freight.getCellData(idx - 1, 'exRate') || 0;

                    var g_Amount = ds_partner_freight.getCellData(idx - 1, 'sellAmtFcrc') || 0;
