                    var g_Amount_US = ds_partner_freight.getCellData(idx - 1, 'usdAmt') || 0;

                    ds_partner_freight.setCellData(row, 'kcomcd', scwin.hd_kcomcd);
                    ds_partner_freight.setCellData(row, 'blNo', cnd_ed_hhblno.getValue()); //update일때.
                    ds_partner_freight.setCellData(row, 'mhno', cnd_lc_mhno.getValue()); //update일때.
                    ds_partner_freight.setCellData(row, 'odrNo', ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition() || 0, 'odrNo'));
                    ds_partner_freight.setCellData(row, 'drCrCls', 'D'); //D/C				
                    ds_partner_freight.setCellData(row, 'locPtnCls', '2'); //국내 : 1, 해외 :2 	
                    ds_partner_freight.setCellData(row, 'mblHblCls', 'H'); //house/master
                    ds_partner_freight.setCellData(row, 'seaAirCls', 'S'); // sea/air	
                    ds_partner_freight.setCellData(row, 'ppccCls', ds_houseblList_freight.getCellData(0, 'hhpcgb'));  	//pp/cc											
                    ds_partner_freight.setCellData(row, 'inpid', scwin.vUserId);

                    ds_partner_freight.setCellData(row, 'bilgClntNo', ed_hhagent_freight.getValue());
                    ds_partner_freight.setCellData(row, 'bilgClntNm', txt_hhagentnm_freight.getValue());   //partner name				
                    ds_partner_freight.setCellData(row, 'rsltsStdDt', ed_creadyDt.getValue());   //실적일	
                    ds_partner_freight.setCellData(row, 'exRateTyp', lc_selling_hhexgb_freight.getValue());  //exgb			

                    ds_partner_freight.setCellData(row, 'sellUpr', g_Rate);
                    ds_partner_freight.setCellData(row, 'exRate', g_Ex_Rate);

                    ds_partner_freight.setCellData(row, 'sellAmtFcrc', g_Amount);
                    ds_partner_freight.setCellData(row, 'sellAmt', g_Amount_W);
                    ds_partner_freight.setCellData(row, 'usdAmt', g_Amount_US);

                    //unit처리.
                    scwin.f_partnerUnitLoading_freight();
                    ds_partner_freight.setCellData(row, 'fareUnit', ds_partnerUnit_freight.getCellData(0, 'code'));
                    scwin.f_packageRatePartnerLoading_freight(row, '');

                    // gr_partner_freight.Focus();
                }
            }
            break;


        case 3:  	// Buying
            if (cnd_ed_hhblno.getValue() == '') {
                $c.gus.cfAlertMsg('No data found./Could not find any relevant data.'); //  해당되는 자료가 존재하지 않습니다
            } else {
                for (var i = 0; i < rowMake_buying; i++) {

                    if (ds_buying_freight.getTotalRow() == 0 || ds_buying_freight.getTotalRow() == ds_buying_freight.getRowPosition()) {
                        idx = ds_buying_freight.insertRow();
                        row = idx;
                    } else {
                        idx = ds_buying_freight.insertRow(ds_buying_freight.getRowPosition() + 1);
                        row = idx;
                    }

                    var g_Rate = ds_buying_freight.getCellData(idx - 1, 'pchsUpr') || 0;
                    var g_Ex_Rate = ds_buying_freight.getCellData(idx - 1, 'exRate') || 0;

                    var g_Amount = ds_buying_freight.getCellData(idx - 1, 'pchsAmtFcrc') || 0;
                    var g_Amount_W = ds_buying_freight.getCellData(idx - 1, 'pchsAmt') || 0;
                    var g_Amount_US = ds_buying_freight.getCellData(idx - 1, 'usdAmt') || 0;

                    ds_buying_freight.setCellData(row, 'kcomcd', scwin.hd_kcomcd);
                    ds_buying_freight.setCellData(row, 'blNo', cnd_ed_hhblno.getValue()); //update일때.
                    ds_buying_freight.setCellData(row, 'mhno', cnd_lc_mhno.getValue()); //update일때.
                    ds_buying_freight.setCellData(row, 'odrNo', ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition() || 0, 'odrNo'));
                    ds_buying_freight.setCellData(row, 'locPtnCls', '1'); //국내 : 1, 해외 :2 			
                    ds_buying_freight.setCellData(row, 'mblHblCls', 'H'); //house/master	
                    ds_buying_freight.setCellData(row, 'seaAirCls', 'S'); // sea/air
                    ds_buying_freight.setCellData(row, 'drCrCls', 'C'); // DR/CR		
                    ds_buying_freight.setCellData(row, 'ppccCls', ds_houseblList_freight.getCellData(0, 'hhpcgb'));  		 //pp/cc																	
                    ds_buying_freight.setCellData(row, 'inpid', scwin.vUserId);

                    ds_buying_freight.setCellData(row, 'pchsClntNo', ed_hhliner_freight.getValue());
                    ds_buying_freight.setCellData(row, 'pchsClntNm', txt_hhlinernm_freight.getValue());   //Liner name					
                    ds_buying_freight.setCellData(row, 'rsltsStdDt', ed_creadyDt.getValue());  	 //실적일		
                    ds_buying_freight.setCellData(row, 'exRateTyp', lc_selling_hhexgb_freight.getValue());  //exgb				
                    ds_buying_freight.setCellData(row, 'pchsTyp', '1');

                    ds_buying_freight.setCellData(row, 'pchsUpr', g_Rate);
                    ds_buying_freight.setCellData(row, 'exRate', g_Ex_Rate);

                    ds_buying_freight.setCellData(row, 'pchsAmtFcrc', g_Amount);
                    ds_buying_freight.setCellData(row, 'pchsAmt', g_Amount_W);
                    ds_buying_freight.setCellData(row, 'usdAmt', g_Amount_US);


                    //gr_buying_freight.ColumnProp('sellDeptCd', 'edit',  'none';	
                    //unit처리.
                    scwin.f_buyingUnitLoading_freight();
                    ds_buying_freight.setCellData(row, 'fareUnit', ds_buyingUnit_freight.getCellData(0, 'code'));
                    scwin.f_packageRateBuyingLoading_freight(row, '');

                    // gr_buying_freight.Focus();
                }
            }
            break;

        default:
            break;
    }
};

//---------------------------------------------------------
// 행삭제 (WebSquare)
//---------------------------------------------------------
scwin.f_deleteRow_freight1 = function () {
    scwin.f_deleteRow_freight(1);
}

scwin.f_deleteRow_freight2 = function () {
    scwin.f_deleteRow_freight(2);
}

scwin.f_deleteRow_freight3 = function () {
    scwin.f_deleteRow_freight(3);
}

scwin.f_deleteRow_freight = async function (disGubun) {
    var ds = (disGubun == 1) ? ds_selling_freight
        : (disGubun == 2) ? ds_partner_freight
            : ds_buying_freight;

    var chkCol = 'chk';
    var certCol = (disGubun == 3) ? 'pchsCertiNo' : 'certiNo';

    for (let i = ds.getRowCount() - 1; i >= 0; i--) {
        if (ds.getCellData(i, chkCol) != 'T') continue;

        // Invoice 존재
        if (String(ds.getCellData(i, certCol) || '') != '') {
            // await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ['Invoice No', 'delete']);
            await $c.win.alert('Invoice No operation cannot be performed for delete.');
            return;
        }

        // 확정 체크(Partner/Buying만)
        if (disGubun != 1 && ds.getCellData(i, 'dcsnClsCd') == '확정') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ['확정', 'delete']);
            return;
        }
        if (ds.getRowStatus(i) != 'C') {
            ds.deleteRow(i);
        } else {
            ds.removeRow(i);
        }
    }
};

//---------------------------------------------------------
// 행취소 (WebSquare)
//---------------------------------------------------------
scwin.f_cancelRow_freight1 = function () {
    scwin.f_cancelRow_freight(1);
};

scwin.f_cancelRow_freight2 = function () {
    scwin.f_cancelRow_freight(2);
};

scwin.f_cancelRow_freight3 = function () {
    scwin.f_cancelRow_freight(3);
};

scwin.f_cancelRow_freight = function (disGubun) {
    if (disGubun == 1) {
        for (var i = ds_selling_freight.getTotalRow() - 1; i >= 0; i--) {
            if (ds_selling_freight.getRowStatus(i) == 'C') {
                ds_selling_freight.removeRow(i);
            } else {
                ds_selling_freight.undoRow(i);
            }
        }
    } else if (disGubun == 2) {
        for (var i = ds_partner_freight.getTotalRow() - 1; i >= 0; i--) {
            if (ds_partner_freight.getRowStatus(i) == 'C') {
                ds_partner_freight.removeRow(i);
            } else {
                ds_partner_freight.undoRow(i);
            }
        }
    } else if (disGubun == 3) {
        for (var i = ds_buying_freight.getTotalRow() - 1; i >= 0; i--) {
            if (ds_buying_freight.getRowStatus(i) == 'C') {
                ds_buying_freight.removeRow(i);
            } else {
                ds_buying_freight.undoRow(i);
            }
        }
    }
};

//-------------------------------------------------------------------------
// ds에서 code값이 존재하는지 체크 (code컬럼명/프로젝트 표준에 맞게 변경)
// - 성공: true
// - 실패: false
//-------------------------------------------------------------------------
scwin._existsCode = function (ds, codeCol, codeVal) {
    if (codeVal == '') return true;

    // 일반적으로 code 컬럼이 'code'일 가능성이 높음
    for (var i = 1; i <= ds.getRowCount(); i++) {
        if (String(ds.getCellData(i, codeCol)) == String(codeVal)) return true;
    }
    return false;
};

//---------------------------------------------------------
// validate (WebSquare)
//---------------------------------------------------------
scwin.f_validate_freight = async function () {

    // 1) 기본 validate (프로젝트 공통 그대로 사용)
    if (!$c.gus.cfValidate([ed_selling_hhcurdt_freight, gr_selling_freight, gr_partner_freight, gr_buying_freight])) { // , scwin.ed_hhetd_freight
        return false;
    }

    // 2) 필수값
    if (cnd_ed_hhblno.getValue() == '') {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['House B/L']);
        cnd_ed_hhblno.focus();
        return false;
    }

    // if (scwin.ed_hhetd_freight == '') {
    //     await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['ETD']);
    //     // scwin.ed_hhetd_freight.focus();
    //     return false;
    // }

    // 3) Container Type value check (원본 ValueRow 대체)
    var c1 = ed_hhcnt1type_freight.getValue();
    var c2 = ed_hhcnt2type_freight.getValue();
    var c3 = ed_hhcnt3type_freight.getValue();
    var c4 = ed_hhcnt4type_freight.getValue();

    if (!scwin._existsCode(ds_containerType_freight, 'code', c1)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']);
        ed_hhcnt1type_freight.focus();
        return false;
    }
    if (!scwin._existsCode(ds_containerType_freight, 'code', c2)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']);
        ed_hhcnt2type_freight.focus();
        return false;
    }
    if (!scwin._existsCode(ds_containerType_freight, 'code', c3)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']);
        ed_hhcnt3type_freight.focus();
        return false;
    }
    if (!scwin._existsCode(ds_containerType_freight, 'code', c4)) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']);
        ed_hhcnt4type_freight.focus();
        return false;
    }

    // 4) Selling 필수 컬럼
    for (var i = 0; i < ds_selling_freight.getRowCount(); i++) {
        if (ds_selling_freight.getCellData(i, 'bilgClntNm') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer Name']);
            gr_selling_freight.focus();
            gr_selling_freight.setFocusedCell(i, 'bilgClntNm');
            return false;
        }
        if (ds_selling_freight.getCellData(i, 'bilgClntNo') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer']);
            gr_selling_freight.focus();
            gr_selling_freight.setFocusedCell(i, 'bilgClntNo');
            return false;
        }
        if (ds_selling_freight.getCellData(i, 'fareEngCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['F/Code']);
            gr_selling_freight.focus();
            gr_selling_freight.setFocusedCell(i, 'fareEngCd');
            return false;
        }
        if (ds_selling_freight.getCellData(i, 'crcCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Currency']);
            gr_selling_freight.focus();
            gr_selling_freight.setFocusedCell(i, 'crcCd');
            return false;
        }
        if (ds_selling_freight.getCellData(i, 'fareUnit') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Unit']);
            gr_selling_freight.focus();
            gr_selling_freight.setFocusedCell(i, 'fareUnit');
            return false;
        }
    }

    // 5) Partner 필수 컬럼
    for (var j = 0; j < ds_partner_freight.getRowCount(); j++) {
        if (ds_partner_freight.getCellData(j, 'bilgClntNo') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer']);
            gr_partner_freight.focus();
            gr_partner_freight.setFocusedCell(j, 'bilgClntNo');
            return false;
        }
        if (ds_partner_freight.getCellData(j, 'bilgClntNm') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer Name']);
            gr_partner_freight.focus();
            gr_partner_freight.setFocusedCell(j, 'bilgClntNm');
            return false;
        }
        if (ds_partner_freight.getCellData(j, 'fareEngCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['F/Code']);
            gr_partner_freight.focus();
            gr_partner_freight.setFocusedCell(j, 'fareEngCd');
            return false;
        }
        if (ds_partner_freight.getCellData(j, 'drCrCls') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['D/C']);
            gr_partner_freight.focus();
            gr_partner_freight.setFocusedCell(j, 'drCrCls');
            return false;
        }
        if (ds_partner_freight.getCellData(j, 'crcCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Currency']);
            gr_partner_freight.focus();
            gr_partner_freight.setFocusedCell(j, 'crcCd');
            return false;
        }
        if (ds_partner_freight.getCellData(j, 'fareUnit') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Unit']);
            gr_partner_freight.focus();
            gr_partner_freight.setFocusedCell(j, 'fareUnit');
            return false;
        }
    }

    // 6) Buying 필수 컬럼
    for (var k = 0; k < ds_buying_freight.getRowCount(); k++) {
        if (ds_buying_freight.getCellData(k, 'pchsTyp') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Type']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'pchsTyp');
            return false;
        }
        if (ds_buying_freight.getCellData(k, 'pchsClntNo') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'pchsClntNo');
            return false;
        }
        if (ds_buying_freight.getCellData(k, 'pchsClntNm') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Customer Name']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'pchsClntNm');
            return false;
        }
        if (ds_buying_freight.getCellData(k, 'fareEngCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['F/Code']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'fareEngCd');
            return false;
        }
        if (ds_buying_freight.getCellData(k, 'crcCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Currency']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'crcCd');
            return false;
        }
        if (ds_buying_freight.getCellData(k, 'fareUnit') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Unit']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'fareUnit');
            return false;
        }
        // Inner Dept (pchsTyp=3)
        if (ds_buying_freight.getCellData(k, 'pchsTyp') == '3' && ds_buying_freight.getCellData(k, 'sellDeptCd') == '') {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ['Inner Department']);
            gr_buying_freight.focus();
            gr_buying_freight.setFocusedCell(k, 'sellDeptCd');
            return false;
        }
    }

    // 7) VAT 체크 (Selling)
    for (var s = 0; s < ds_selling_freight.getRowCount(); s++) {
        var vatYn = Number(ds_selling_freight.getCellData(s, 'vatYn'));
        var vatAmt = Number(ds_selling_freight.getCellData(s, 'vatAmt'));
        var sellAmt = Number(ds_selling_freight.getCellData(s, 'sellAmt'));

        if (vatYn == 0) {
            if (vatAmt > 0) {
                $c.win.alert('영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List ' + s + '번째 데이터를 확인하세요.');
                gr_selling_freight.focus();
                return false;
            }
        }

        if (vatYn == 1) {
            if (Math.abs(Math.round(sellAmt * 0.1) - vatAmt) > 1) {
                $c.win.alert('VAT 금액은 Amount(W)금액의 10%입니다. \nSelling List ' + s + '번째 VAT 금액을 확인하세요.');
                gr_selling_freight.focus();
                gr_selling_freight.setFocusedCell(s, 'vatAmt');
                return false;
            }
        }
    }

    // 8) VAT 체크 (Buying) - 원본: vat 컬럼 사용
    for (var b = 0; b < ds_buying_freight.getRowCount(); b++) {
        var vatYn2 = Number(ds_buying_freight.getCellData(b, 'vatYn'));
        var vat2 = Number(ds_buying_freight.getCellData(b, 'vat'));

        if (vatYn2 == 0 && vat2 > 0) {
            await $c.win.alert('영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List ' + b + '번째 데이터를 확인하세요.');
            gr_buying_freight.focus();
            return false;
        }
    }

    // 9) 공통 Freight Name Validation --- 없는함수 사용중
    // if (!cf_freightNameValidation(ds_selling_freight, ds_partner_freight, ds_buying_freight)) {
    //     return false;
    // }

    return true;
};

//-------------------------------------------------------------------------
// Freight 공통팝업(Partner/Customer/Liner + Port/ContainerType) - udc_ilcomCode 통일버전
//-------------------------------------------------------------------------
// 공통: 값 get/set
scwin._wsGetVal = function (comp) {
    if (!comp) return '';
    return String(comp.getValue() || '').trim();
};
scwin._wsSetVal = function (comp, v) {
    if (!comp) return;
    comp.setValue(v);
};

// 공통: rtnList normalize (단건/다건/객체형 대응)
scwin._normalizePopupRtn = function (rtn) {
    if (!rtn || rtn == 'N/A') return null;

    // {list:[...]} 형태
    if (rtn.list && Array.isArray(rtn.list)) rtn = rtn.list;

    // 다건: [[...],[...]] -> 첫 행 사용
    if (Array.isArray(rtn) && rtn.length > 0 && Array.isArray(rtn[0])) return rtn[0];

    // 단건: [...]
    if (Array.isArray(rtn)) return rtn;

    // 객체: {code,name,...}
    var arr = [];
    if (rtn.code != null) arr[0] = rtn.code;
    if (rtn.name != null) arr[1] = rtn.name;
    return arr.length ? arr : null;
};

// 공통: 팝업 오픈 래퍼 (udc_ilcomCode 고정)
scwin._openUdcCommonPopup = function (args, pNoDataCloseTF) {
    // args: {selectId, codeComp, nameComp, extraComps, winCloseTF, colCnt, titles, widths, hideCols,
    //        whereOpt, winW, winH, posY, posX, dupTF, allTF, winTitle, noDataTF, afterFn}

    var onReturn = function (rtnList) {
        var r = scwin._normalizePopupRtn(rtnList);
        if (!r) return;

        // 기본 세팅
        scwin._wsSetVal(args.codeComp, (r[0] || '').trim());
        if (args.nameComp) scwin._wsSetVal(args.nameComp, (r[1] || '').trim());

        // 추가 세팅 (Address 등)
        if (args.extraComps && args.extraComps.length) {
            for (var i = 0; i < args.extraComps.length; i++) {
                scwin._wsSetVal(args.extraComps[i], (r[2 + i] || '').trim());
            }
        }

        if (typeof args.afterFn != 'undefined') args.afterFn(r);
    };

    udc_ilcomCode.setSelectId(args.selectId);

    udc_ilcomCode.ilCommonPopUp(
        onReturn,
        scwin._wsGetVal(args.codeComp),
        args.nameComp ? scwin._wsGetVal(args.nameComp) : '',
        args.winCloseTF,
        args.colCnt,
        args.titles,
        args.widths,
        args.hideCols,
        args.whereOpt || '',
        args.winW || '500',
        args.winH || '500',
        args.posY || '',
        args.posX || '',
        args.dupTF || '',
        args.allTF || 'F',
        args.winTitle || '',
        args.noDataTF || pNoDataCloseTF || ''
    );
};

