//-------------------------------------------------------------------------
// 메뉴 오픈 공통
//-------------------------------------------------------------------------
// title : 탭/메뉴 타이틀
// path  : 이동할 화면 경로
// menuId: 메뉴ID(없으면 path로 대체 가능)
// param : 전달 파라미터 객체
scwin._openMenu = function (title, path, menuId, param) {
    console.log(JSON.stringify(param, null, 4));
    $c.win.openMenu(title, path, menuId, param || {});
};

//-------------------------------------------------------------------------
// Freight 화면이동 공통 파라미터
//-------------------------------------------------------------------------
// (기존 GAUCE: scwin.hd_kcomcd, scwin.hd_hhio, cnd_ed_hhblno.Text, cnd_lc_mhno.Text)
scwin._getCommonParam_freight = function () {
    return {
        kcomcd: (scwin.hd_kcomcd || ''),        // 법인코드
        seaair: 'S',                            // sea:S, air:A
        iogb: (scwin.hd_hhio || ''),          // out:O, in:I
        blno: (cnd_ed_hhblno.getValue() || ''),// house blno
        mblno: '',                             // master blno(원본: '')
        mhno: (cnd_lc_mhno.getValue() || '')  // mhno
    };
};

//-------------------------------------------------------------------------
// 화면이동 (Freight) - GAUCE f_openPgm_freight 변환
//-------------------------------------------------------------------------
// ※ 원본은 URL querystring으로 붙였지만,
//   WebSquare는 openMenu + param 객체로 전달(서버단에서 param을 쿼리로 받도록 되어있다면 자동 매핑)
scwin.f_openPgm_freight = function (name) {

    var p = scwin._getCommonParam_freight();

    if (name == 'Partner') {
        scwin._openMenu(
            'Partner Statement',
            '/ui/il/acc/acpar/ac_104_01_01b.xml',
            'ac_104_01_01b.xml',
            p
        );

    } else if (name == 'Invoice') {
        scwin._openMenu(
            'Invoice',
            '/ui/il/acc/acinv/ac_101_01_01b.xml',
            'ac_101_01_01b.xml',
            p
        );

    } else if (name == 'Profit') {
        scwin._openMenu(
            'Booking Sheet',
            '/ui/il/pfm/pfbs/pe_101_01_01b.xml',
            'pe_101_01_01b.xml',
            p
        );

    } else if (name == 'HouseBLFind') {
        scwin._openMenu(
            'House B/L Search',
            '/ui/il/seaout/sobl/se_105_01_02b.xml',
            'se_105_01_02b.xml',
            { hhio: (scwin.hd_hhio || '') }
        );

    } else if (name == 'HouseBLHeader') {
        scwin._openMenu(
            'Export House B/L',
            '/ui/il/seaout/sobl/se_105_01_01b.xml',
            'se_105_01_01b.xml',
            {
                linkcheck: '2',
                kcomcd: p.kcomcd,
                blno: p.blno,
                mhno: p.mhno
            }
        );

    } else if (name == 'paymentINV') {
        // 원본: /il/acc/acpay/ac_106_01_01b.xml?kcomcd=...&seaair=S&iogb=...&blno=...&mhno=...
        // (mblno 없음)
        scwin._openMenu(
            'Payment Invoice',
            '/ui/il/acc/acpay/ac_106_01_01b.xml',
            'ac_106_01_01b.xml',
            {
                kcomcd: p.kcomcd,
                seaair: p.seaair,
                iogb: p.iogb,
                blno: p.blno,
                mhno: p.mhno
            }
        );
    }
};

