//-------------------------------------------------------------------------
scwin.f_departmentChange = async function () {
    var rtnList = null;
    var buyer = ed_hhbuyer.getValue ? ed_hhbuyer.getValue().trim() : (ed_hhbuyer.value || '').trim();
    var buyerNm = txt_hhbuyernm.getValue ? txt_hhbuyernm.getValue().trim() : (txt_hhbuyernm.value || '').trim();
    if (buyer === '') return;

    var url = '/ui/il/common/xml/ilCommonDeptChange.xml'
    rtnList = await $c.win.openPopup(
        url,
        { width: 460, height: 280, modal: true, popupName: "Department Change" },
        { pdept: buyer, pdeptnm: buyerNm }
        , scwin.popupCallback
    ); // rtnList[0]='N/A', rtnList[1]=ed_newdept, rtnList[2]=txt_newdeptnm

    if (rtnList && rtnList[0] === 'N/A') {
        if ((rtnList[1] || '').trim() === '' || (rtnList[2] || '').trim() === '') return;

        // 부서 변경 프로시저 호출 시작

        dma_DeptChangeParam.set('modrNo', '');
        dma_DeptChangeParam.set('hodrNo', ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'odrNo'));
        dma_DeptChangeParam.set('kcomcd', scwin.hd_kcomcd || "DBEX");
        dma_DeptChangeParam.set('bulkGb', '');
        dma_DeptChangeParam.set('dept', (rtnList[1] || '').trim());
        dma_DeptChangeParam.set('deptnm', (rtnList[2] || '').trim());

        if (await $c.win.confirm($c.data.getMessage("Do you wish to save?"))) {
            await $c.sbm.execute(sbm_DeptChange);

            var spMsg = ds_DeptChangeResult.getCellData(ds_DeptChangeResult.getRowPosition() || 0, 'spMsg');
            var spRtn = ds_DeptChangeResult.getCellData(ds_DeptChangeResult.getRowPosition() || 0, 'spRtn');
            if (spRtn === '0') {
                if (txt_hhbuyernm.setValue) txt_hhbuyernm.setValue((rtnList[2] || '').trim());
                else txt_hhbuyernm.setValue((rtnList[2] || '').trim());
                if (ed_hhbuyer.setValue) ed_hhbuyer.setValue((rtnList[1] || '').trim());
                else ed_hhbuyer.setValue((rtnList[1] || '').trim());

                await $c.win.alert($c.data.getMessage(scwin.MSG_LO_WRN_009));
            } else if (spRtn === '-2') {
                await $c.win.alert($c.data.getMessage(scwin.MSG_LO_WRN_007));
            } else {
                await $c.win.alert($c.data.getMessage(scwin.MSG_LO_WRN_008));
            }
        }
        // 부서 변경 프로시저 호출 끝
    }
};
