//-------------------------------------------------------------------------
// 부서 Change (모달 -> WebSquare popup 권장. 여기서는 기존 showModalDialog 형태 유지/대체)
// INVOICE 있어도 변경 가능 요구로 버튼 활성화
//-------------------------------------------------------------------------
scwin.f_openContainerPopup = async function () {
    var param = {};
    param[0] = scwin.ed_carrierBkNo;

    let opts = {
        id: "ozReportPopup",
        popupName: "ContainerListPopup",
        modal: true,
        type: "browserPopup",
        width: 650,
        height: 610,
        title: "ContainerListPopup"
    };

    data = param;

    rtnList = await $c.win.openPopup("/ui/il/seaout/sobl/se_107_01_01p.xml", opts, data);

    var k = ds_ocContList.getRowCount();

    if (rtnList == null) {
        return false;
    }

    for (var i = k; i < rtnList.length + k; i++) {
        for (var t = 0; t < ds_ocContList.getRowCount(); t++) {
            if (ds_ocContList.getCellData(t, 'mccntno') == rtnList[i - k][3]) {
                await $c.win.alert('Container [' + rtnList[i - k][3] + '] already exists');
                return false;
            }
        }

        ds_ocContList.insertRow();
        ds_ocContList.setCellData(i, 'kcomcd', scwin.hd_kcomcd.getValue ? scwin.hd_kcomcd : scwin.hd_kcomcd.value);
        ds_ocContList.setCellData(i, 'mchblno', cnd_ed_hhblno.getValue ? cnd_ed_hhblno.getValue() : cnd_ed_hhblno.value);
        ds_ocContList.setCellData(i, 'mhno', cnd_lc_mhno.getValue ? cnd_lc_mhno.getValue() : cnd_lc_mhno.value);
        ds_ocContList.setCellData(i, 'inpid', scwin.vUserId);
        ds_ocContList.setCellData(i, 'mccntno', rtnList[i - k][3]);
        ds_ocContList.setCellData(i, 'mctype', rtnList[i - k][7]);
        ds_ocContList.setCellData(i, 'mcseal1', rtnList[i - k][6]);
        ds_ocContList.setCellData(i, 'mcpkg', 0);
        ds_ocContList.setCellData(i, 'mcwgt', 0);
        ds_ocContList.setCellData(i, 'mcmsr', 0);
    }

    return true;
};

