//-------------------------------------------------------------------------
// 엑셀 다운로드 (WebSquare 변환본)
// - confirm => await $c.win.confirm()
// - GAUCE: grid.SetExcelTitle + cfGridToExcel  →  $c.data.downloadGridViewExcel
// - dataId.CountRow → dataId.getRowCount()
//-------------------------------------------------------------------------
scwin.f_ExportExcel = async function (dataId, gridId, sheetName) {
    dataId = $p.getComponentById(dataId);
    // rowcount 체크
    var countA = (dataId && true) ? dataId.getRowCount() : 0;
    // if (!(countA > 0)) {
    //     await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
    //     return;
    // }

    // gridId별 제목/파일명
    var sheetName = sheetName;
    var fileName = sheetName;

    // GridView 객체 얻기 (eval 대신 $p.getComponent 사용 권장)
    // 프로젝트에 따라 $p.top().getComponent / $p.getComponent 등 사용
    var gridView = $c.util.getComponent(gridId);
    if (!gridView) {
        await $c.win.alert('그리드 객체를 찾을 수 없습니다 : ' + gridId);
        return;
    }

    // AS-IS SetExcelTitle 매핑
    // skiprow:1  → startRowIndex:2 (제목 1줄 + 헤더)
    var options = {
        fileName: fileName,   // 확장자는 내부에서 처리되거나 필요시 '.xls' 추가
        sheetName: sheetName,
        type: '1',
        headerColor: '#eeeeee',
        startRowIndex: 2
    };

    // 제목(병합/스타일) - colSpan은 그리드 컬럼수에 맞춰 자동 계산(가능한 경우)
    var colSpan = 25;
    try {
        // GridView 컬럼수 추정(프로젝트 GridView API에 맞게 조정 가능)
        colSpan = gridView.getColumnCount();
    } catch (e) { }

    var infoArr = [
        {
            rowIndex: 0,
            colIndex: 0,
            rowSpan: 1,
            colSpan: colSpan,
            text: sheetName,      // value:sheetName
            textAlign: 'center',       // align:center
            fontSize: '12px',         // font-size:12pt
            fontName: '돋움체',        // font-face:'돋움체'
            drawBorder: false           // line-color/line-width:0pt
            // 배경/글자색은 기본값이 흰/검이라 생략(필요시 옵션 지원하면 추가)
        }
    ];

    // 다운로드 실행
    $c.data.downloadGridViewExcel(gridView, options, infoArr);
};


