    }
};


scwin.f_GridCustomerChange = async function (gbn, rtnList) {
    var oldNo = rtnList[1];
    var newNo = rtnList[3];
    var newNm = rtnList[4];

    if (gbn == '0') { // Selling
        if (ds_selling_freight.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Selling Information']);
            return;
        }
        if (!(await $c.win.confirm("Do you wish to save?"))) return;

        scwin.applyClientChangeToFreight(ds_selling_freight, {
            certiField: 'certiNo',
            matchField: 'bilgClntNo',
            setNoField: 'bilgClntNo',
            setNmField: 'bilgClntNm',
            oldNo: oldNo,
            newNo: newNo,
            newNm: newNm
        });

    } else if (gbn == '1') { // Partner
        if (ds_partner_freight.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Partner Information']);
            return;
        }
        if (!(await $c.win.confirm("Do you wish to save?"))) return;

        scwin.applyClientChangeToFreight(ds_partner_freight, {
            certiField: 'certiNo',
            matchField: 'bilgClntNo',
            setNoField: 'bilgClntNo',
            setNmField: 'bilgClntNm',
            oldNo: oldNo,
            newNo: newNo,
            newNm: newNm
        });

    } else if (gbn == '2') { // Buying
        if (ds_buying_freight.getRowCount() == 0) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Buying Information']);
            return;
        }
        if (!(await $c.win.confirm("Do you wish to save?"))) return;

        scwin.applyClientChangeToFreight(ds_buying_freight, {
            certiField: 'pchsCertiNo',
            matchField: 'pchsClntNo',
            setNoField: 'pchsClntNo',
            setNmField: 'pchsClntNm',
            oldNo: oldNo,
            newNo: newNo,
            newNm: newNm
        });
    }
};

