// [WebSquare] sbm_retrieveOcr submitdone
scwin.sbm_retrieveOcr_submitdone = async function (e) {
    function makeMultiLine(ds, row, cols) {
        var list = cols.map(function (col) {
            return ds.getCellData(row, col);
        });

        // 마지막 값 위치 찾기
        var lastIdx = -1;
        for (var i = list.length - 1; i >= 0; i--) {
            if (list[i] && String(list[i]).trim() !== "") {
                lastIdx = i;
                break;
            }
        }

        if (lastIdx === -1) return "";

        return list.slice(0, lastIdx + 1).join('\n');
    }
    if (ds_houseblList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
        scwin.f_Set('INIT');
        scwin.f_Check(); // Object Check
        return;
    }

    var ds_houseblList_export = ds_houseblList.getRowJSON(0);
    var ds_ocContList_export = ds_ocContList.getRowJSON(0);

    scwin.f_Create();

    lc_hhbkgseq.setValue('');
    ds_houseblList.removeAll();
    ds_houseblList.insertRow();
    ds_houseblList.setRowJSON(0, ds_houseblList_export, true);
    ds_ocContList.removeAll();
    ds_ocContList.insertRow();
    ds_ocContList.setRowJSON(0, ds_ocContList_export, true);
    cnd_ed_hhblno.setValue(ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhblno') /* TODO: GAUCE->WS row base ?? */);
    cnd_lc_autono.setSelectedIndex(2);

    ed_totcnt.setValue(ds_ocContList.getTotalRow()); // 조회된 건수를Grid 하단에 표시한다.
    ed_eltotcnt.setValue(ds_ocElList.getTotalRow()); // 조회된 건수를Grid 하단에 표시한다.
    var v_totPkg = 0;
    var v_totWgt = 0;
    var v_totMsr = 0;
    var v_eltotPkg = 0;
    var v_eltotWgt = 0;

    for (i = 1; i <= ds_ocContList.getRowCount(); i++) {
        v_totPkg += ds_ocContList.getCellData((i) - 1, 'mcpkg');
        v_totWgt += ds_ocContList.getCellData((i) - 1, 'mcwgt');
        v_totMsr += ds_ocContList.getCellData((i) - 1, 'mcmsr');
    }

    for (i = 1; i <= ds_ocElList.getRowCount(); i++) {
        v_eltotPkg += ds_ocElList.getCellData((i) - 1, 'pkg');
        v_eltotWgt += ds_ocElList.getCellData((i) - 1, 'wgt');
    }
    ed_totpkg.setValue(v_totPkg);
    ed_totwgt.setValue(v_totWgt);
    ed_totmsr.setValue(v_totMsr);
    ed_eltotpkg.setValue(v_eltotPkg);
    ed_eltotwgt.setValue(v_eltotWgt);
    scwin.f_invoiceCheck(); // invoice Check
    scwin.f_ContractInfo_booking();
    scwin.f_retrieveCarrierBkNo();
    ds_houseblList.setRowPosition(0);
    if (ds_houseblList.getRowCount() > 0) {
        var row = ds_houseblList.getRowPosition() || 0;

        // SHIPPER
        ta_hhs.setValue(
            makeMultiLine(ds_houseblList, row, ['hhs1', 'hhs2', 'hhs3', 'hhs4', 'hhs5'])
        );

        // CONSIGNEE
        ta_hhc.setValue(
            makeMultiLine(ds_houseblList, row, ['hhc1', 'hhc2', 'hhc3', 'hhc4', 'hhc5'])
        );

        // NOTIFY
        ta_hhn.setValue(
            makeMultiLine(ds_houseblList, row, ['hhn1', 'hhn2', 'hhn3', 'hhn4', 'hhn5'])
        );
        // ta_hhs.setValue(ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhs1') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhs2') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhs3') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhs4') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhs5') /* TODO: GAUCE->WS row base ?? */
        // );
        // ta_hhc.setValue(ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhc1') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhc2') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhc3') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhc4') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, 'hhc5') /* TODO: GAUCE->WS row base ?? */
        // );
        // ta_hhn.setValue(ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhn1') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhn2') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhn3') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhn4') /* TODO: GAUCE->WS row base ?? */
        //     + '\n' + ds_houseblList.getCellData(ds_houseblList.getRowPosition(), 'hhn5') /* TODO: GAUCE->WS row base ?? */
        // );
        if (lc_hhbltype.getValue() == 'B') {
            if (ed_hhgwgt.getValue() > 0) {

                ed_hhmt.setValue(ed_hhgwgt.getValue() / 1000);
            }
        }
        scwin.f_Retrieve_booking();
    }
    if (ds_partnerInfo.getRowCount() > 0) {
        txa_agentAdress.setValue(ds_partnerInfo.getCellData(ds_partnerInfo.getRowPosition() || 0, 'partnerAddr1') /* TODO: GAUCE->WS row base ?? */
            + '\n' + ds_partnerInfo.getCellData(ds_partnerInfo.getRowPosition() || 0, 'partnerAddr2') /* TODO: GAUCE->WS row base ?? */
            + '\n' + ds_partnerInfo.getCellData(ds_partnerInfo.getRowPosition() || 0, 'partnerAddr3') /* TODO: GAUCE->WS row base ?? */
            + '\n' + ds_partnerInfo.getCellData(ds_partnerInfo.getRowPosition() || 0, 'partnerAddr4') /* TODO: GAUCE->WS row base ?? */
            + '\n' + ds_partnerInfo.getCellData(ds_partnerInfo.getRowPosition() || 0, 'partnerAddr5') /* TODO: GAUCE->WS row base ?? */
        );
        txa = txa_agentAdress.getValue().split("\n");
        if (txa[0] == "" && txa[1] == "" && txa[2] == "" && txa[3] == "" && txa[4] == "") txa_agentAdress.setValue("");
    } else {
        ds_partnerInfo.removeAll();
        ds_partnerInfo.insertRow(0);
        ds_partnerInfo.setCellData(0, 'blno', cnd_ed_hhblno.getValue());
    }

    // B/L
    ed_hhobl.setValue('3'); // O B/L
    lc_hhcoload.setSelectedIndex(0); // Co-Load
    rd_hhdanggb.setValue('N'); // Dangerous
    lc_hhisunm.setSelectedIndex(1); // Issued At
    lc_hhprenm.setSelectedIndex(0); // Freight Term
    lc_hhstype.setSelectedIndex(0); // Service Term

    // Container
    chb_hhp1.checkAll(true);
    chb_hhp2.checkAll(false);
    chb_hhp3.checkAll(false);
    chb_hhp4.checkAll(true);
    chb_hhp5.checkAll(false);
    chb_hhp6.checkAll(true);
    txt_hhsay.setValue(' CONTAINER ONLY');
    scwin.gptYn = true;
    lc_contractno_booking.setSelectedIndex(-1);
    setTimeout(function () {
        cnd_ed_hhblno.setValue(ds_houseblList.getCellData(0, "hhblno"));
        scwin.f_setFileUpDownFrame();
    }, 100)
};

// [WebSquare] sbm_retrieveOcrInvoice submitdone
scwin.sbm_retrieveOcrInvoice_submitdone = async function (e) {
    if (ds_buying_freight_temp.getRowCount() == 0) {
        await $c.win.alert('해당 B/L에 조회된 Invoice가 존재하지 않습니다.');
        return;
    }

    // 조회 상태라면, Update 상태로 변경. 그 외는 그대로 둠
    if (scwin.statusFlag == '') {
        scwin.f_Update();
    }

    // Buying Freight
    var buying_temp_data = ds_buying_freight_temp.ExportData(1, ds_buying_freight_temp.getRowCount(), true);
    ds_buying_freight.ImportData(buying_temp_data);


    // Frieght 기본값 설정
    for (var i = 1; i <= ds_buying_freight.getRowCount(); i++) {
        ds_buying_freight.setCellData((i) - 1, 'mhno', cnd_lc_mhno.getValue()); // update일때.
        ds_buying_freight.setCellData((i) - 1, 'odrNo',
            ds_houseblList_freight.getCellData(ds_houseblList_freight.getRowPosition(), 'odrNo'));
        ds_buying_freight.setCellData((i) - 1, 'ppccCls', scwin.hd_hhpcgb_freight); // pp/cc
        ds_buying_freight.setCellData((i) - 1, 'inpid', scwin.vUserId);
        // ds_buying_freight.setCellData((i) - 1, 'rsltsStdDt', ed_creadyDt.getValue());  	 //실적일
        ds_buying_freight.setCellData((i) - 1, 'exRateTyp', lc_selling_hhexgb_freight.getValue());  // exgb
        ds_buying_freight.setCellData((i) - 1, 'pchsTyp', '1');

        //ds_buying_freight.getCellData((i) - 1, 'pchsClntNo'));
        //ds_buying_freight.getCellData((i) - 1, 'pchsClntNm'));   //Liner name
        //f_UnitLoading_freight
        //ds_buying_freight.getCellData((row) - 1, 'fareUnit')- 1, 'code'));
        //scwin.f_packageRateBuyingLoading_freight(row,'');
    }

    await $c.win.alert('데이터를 성공적으로 불러왔습니다.');
};

