// ==
// Container Type 공통 체크 (freight)
// ==
scwin._checkContainerType_freight = async function (inputComp) {
    var v = inputComp.getValue();
    if (v == '') return true;

    // GAUCE: ds_containerType_freight.getCellData(0, code)
    // WS: 코드 존재 여부 확인
    var matched = ds_containerType_freight
        ? ds_containerType_freight.getMatchedData('code', v)
        : -1;

    // 값이 없을 때 (-1 또는 '0' 방어)
    if (matched == -1 || matched == '0') {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ['Container Type']);
        return false;
    }
    return true;
};

