    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await $c.gus.cfAlertMsg(MSG_CM_INF_001); //  성공적으로 저장하였습니다.

    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno, true);
    scwin.f_Retrieve();
    cnd_ed_hhblno.focus();
    scwin.f_Set('SAVE');
};

