// [GAUCE] for=lc_pathCd event=OnDropDown

// [GAUCE] for=ds_houseblList event=OnLoadCompleted(rowcnt)
scwin.ds_houseblList_ondataload = async function () {
    function makeTextAreaValue(ds, row, cols) {
        var arr = [];

        for (var i = 0; i < cols.length; i++) {
            arr.push(ds.getCellData(row, cols[i]) || '');
        }

        // 뒤에서부터 마지막 값 있는 위치 찾기
        var lastIdx = -1;
        for (var j = arr.length - 1; j >= 0; j--) {
            if (String(arr[j]).trim() !== '') {
                lastIdx = j;
                break;
            }
        }

        // 전부 빈값이면 빈값
        if (lastIdx < 0) {
            return '';
        }

        // 마지막 값까지만 자르기
        return arr.slice(0, lastIdx + 1).join('\n');
    }
    var row = ds_houseblList.getRowPosition();

    // path 조회
    if (ds_houseblList.getCellData(row, 'pathCd') !== '') {

        dma_condition_path.set('hhactcust', ed_hhactcust.getValue());
        dma_condition_path.set('path', ds_houseblList.getCellData(row, 'pathCd'));
        dma_condition_path.set('hhblno', '');

        await $c.sbm.execute(sbm_retrieve_path);
    }

    // House B/L 정보 세팅
    if (ds_houseblList.getRowCount() > 0) {
        ta_hhs.setValue(
            makeTextAreaValue(ds_houseblList, row, ['hhs1', 'hhs2', 'hhs3', 'hhs4', 'hhs5'])
            + "\n");

        ta_hhc.setValue(
            makeTextAreaValue(ds_houseblList, row, ['hhc1', 'hhc2', 'hhc3', 'hhc4', 'hhc5'])
            + "\n");

        ta_hhn.setValue(
            makeTextAreaValue(ds_houseblList, row, ['hhn1', 'hhn2', 'hhn3', 'hhn4', 'hhn5'])
            + "\n");
        // ta_hhs.setValue(
        //     (ds_houseblList.getCellData(row, 'hhs1') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhs2') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhs3') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhs4') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhs5') || '')
        // );

        // ta_hhc.setValue(
        //     (ds_houseblList.getCellData(row, 'hhc1') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhc2') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhc3') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhc4') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhc5') || '')
        // );

        // ta_hhn.setValue(
        //     (ds_houseblList.getCellData(row, 'hhn1') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhn2') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhn3') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhn4') || '') + '\n' +
        //     (ds_houseblList.getCellData(row, 'hhn5') || '')
        // );

        // B/L TYPE = B 인 경우 중량 계산
        if (lc_hhbltype.getValue() === 'B') {
            var gwgt = Number(ed_hhgwgt.getValue() || 0);
            if (gwgt > 0) {
                ed_hhmt.setValue(gwgt / 1000);
            }
        }

        scwin.f_Retrieve_booking();
    }

    // 파트너 주소 세팅
    if (ds_partnerInfo.getRowCount() > 0) {

        var prow = ds_partnerInfo.getRowPosition();

        txa_agentAdress.setValue(
            (ds_partnerInfo.getCellData(prow, 'partnerAddr1') || '') + '\n' +
            (ds_partnerInfo.getCellData(prow, 'partnerAddr2') || '') + '\n' +
            (ds_partnerInfo.getCellData(prow, 'partnerAddr3') || '') + '\n' +
            (ds_partnerInfo.getCellData(prow, 'partnerAddr4') || '') + '\n' +
            (ds_partnerInfo.getCellData(prow, 'partnerAddr5') || '')
        );

        txa = txa_agentAdress.getValue().split("\n");
        if (txa[0] == "" && txa[1] == "" && txa[2] == "" && txa[3] == "" && txa[4] == "") txa_agentAdress.setValue("");
    } else {
        ds_partnerInfo.removeAll();
        ds_partnerInfo.insertRow(0);
        ds_partnerInfo.setCellData(0, 'blno', cnd_ed_hhblno.getValue());
    }
};

