scwin.f_addCntr = function (gubun) {
    function isEmpty(val) {
        if (val == null || val == undefined || val === "") {
            return 0;
        }
        return Number(val);
    }
    //   		tr_retrieveCntr.Post();
    var hhcnt1 = isEmpty(ed_hhcnt1.getValue());
    var hhcnt2 = isEmpty(ed_hhcnt2.getValue());
    var hhcnt3 = isEmpty(ed_hhcnt3.getValue());
    var hhcnt4 = isEmpty(ed_hhcnt4.getValue());
    var hhcnt = parseInt(hhcnt1) + parseInt(hhcnt2) + parseInt(hhcnt3) + parseInt(hhcnt4);

    var hhcnt1type = ed_hhcnt1type.getValue();
    var hhcnt2type = ed_hhcnt2type.getValue();
    var hhcnt3type = ed_hhcnt3type.getValue();
    var hhcnt4type = ed_hhcnt4type.getValue();

    var hhpkg = parseInt(isEmpty(ed_hhpkg.getValue()) / hhcnt);
    var hhgwgt = (isEmpty(ed_hhgwgt.getValue()) / hhcnt).toFixed(3);
    var hhmsr = (isEmpty(ed_hhmsr.getValue()) / hhcnt).toFixed(3);

    var hhpkgSum = 0;
    var hhgwgtSum = 0;
    var hhmsrSum = 0;
    var cntSum = 1;

    //컨테이너 리스트 초기화
    ds_ocContList.setJSON([]);

    for (var i = 0; i < hhcnt1; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "inpid", scwin.vUserId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mctype", hhcnt1type);
        if (gubun == "2") {
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkg", hhpkg);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcwgt", hhgwgt);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcmsr", hhmsr);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkgcd", ed_hhunitcd.getValue());
            if (cntSum != hhcnt) {
                hhpkgSum = isEmpty(hhpkgSum) + isEmpty(hhpkg);
                hhgwgtSum = isEmpty(hhgwgtSum) + isEmpty(hhgwgt);
                hhmsrSum = isEmpty(hhmsrSum) + isEmpty(hhmsr);
            }
            cntSum++;
        }

    }
    for (var i = 0; i < hhcnt2; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "inpid", scwin.vUserId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mctype", hhcnt2type);
        if (gubun == "2") {
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkgcd", ed_hhunitcd.getValue());
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkg", hhpkg);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcwgt", hhgwgt);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcmsr", hhmsr);

            if (cntSum != hhcnt) {
                hhpkgSum = isEmpty(hhpkgSum) + isEmpty(hhpkg);
                hhgwgtSum = isEmpty(hhgwgtSum) + isEmpty(hhgwgt);
                hhmsrSum = isEmpty(hhmsrSum) + isEmpty(hhmsr);
            }
            cntSum++;
        }
    }
    for (var i = 0; i < hhcnt3; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "inpid", scwin.vUserId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mctype", hhcnt3type);
        if (gubun == "2") {
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkgcd", ed_hhunitcd.getValue());
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkg", hhpkg);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcwgt", hhgwgt);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcmsr", hhmsr);

            if (cntSum != hhcnt) {
                hhpkgSum = isEmpty(hhpkgSum) + isEmpty(hhpkg);
                hhgwgtSum = isEmpty(hhgwgtSum) + isEmpty(hhgwgt);
                hhmsrSum = isEmpty(hhmsrSum) + isEmpty(hhmsr);
            }
            cntSum++;
        }
    }
    for (var i = 0; i < hhcnt4; i++) {
        ds_ocContList.insertRow();
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mchblno", cnd_ed_hhblno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "inpid", scwin.vUserId);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mctype", hhcnt4type);
        if (gubun == "2") {
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkgcd", ed_hhunitcd.getValue());
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkg", hhpkg);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcwgt", hhgwgt);
            ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcmsr", hhmsr);

            if (cntSum != hhcnt) {
                hhpkgSum = isEmpty(hhpkgSum) + isEmpty(hhpkg);
                hhgwgtSum = isEmpty(hhgwgtSum) + isEmpty(hhgwgt);
                hhmsrSum = isEmpty(hhmsrSum) + isEmpty(hhmsr);
            }
            cntSum++;
        }
    }
    ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkg", "0");
    ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcwgt", "0");
    ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcmsr", "0");
    if (gubun == "2") {
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcpkg", isEmpty(ed_hhpkg.getValue()) - hhpkgSum);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcwgt", isEmpty(ed_hhgwgt.getValue()) - hhgwgtSum);
        ds_ocContList.setCellData(ds_ocContList.getRowPosition() || 0, "mcmsr", isEmpty(ed_hhmsr.getValue()) - hhmsrSum);
    }
}

