scwin.gr_selling_freight_onafteredit = function (rowIndex, columnIndex, value) {
    var row = rowIndex;
    var col = gr_selling_freight.getColumnID(columnIndex);
    switch (col) {
        case 'bilgClntNo':
            scwin.f_PopUpGrid_freight('SellingCustomer', row, 'F', 'F', 'F');
            break;
        case 'fareEngCd':
            scwin.f_PopUpGrid_freight('SellingFcode', row, 'F', 'F', 'F');
            break;
        default:
            break;
    }

    Row = rowIndex;
    Colid = gr_selling_freight.getColumnID(columnIndex);
    olddata = value;
    switch (Colid) {
        case "bilgClntNo":
            if (ds_selling_freight.getCellData(Row, Colid).trim() != "") {
                ds_selling_freight.setCellData(Row, "bilgClntNm", "");
                scwin.f_PopUpGrid_freight("SellingCustomer", Row, "T", "F", "F");
            } else if (ds_selling_freight.getCellData(Row, Colid).trim() == "") {
                ds_selling_freight.setCellData(Row, "bilgClntNo", "");
                ds_selling_freight.setCellData(Row, "bilgClntNm", "");
            }
            break;

        case "fareEngCd":
            if (ds_selling_freight.getCellData(Row, Colid).trim() != "") {
                ds_selling_freight.setCellData(Row, "fareEngNm", "");
                scwin.f_PopUpGrid_freight("SellingFcode", Row, "T", "F", "F");
            } else if (ds_selling_freight.getCellData(Row, Colid).trim() == "") {
                ds_selling_freight.setCellData(Row, "fareEngCd", "");
                ds_selling_freight.setCellData(Row, "fareEngNm", "");
            }
            scwin.f_sellingAmtFcrc_freight(Row, Colid, olddata);
            scwin.f_sellingAmt_freight(Row, Colid, olddata);
            scwin.f_sellingVat_freight(Row, Colid, olddata);
            scwin.f_sellingUsdAmt_freight(Row, Colid, olddata);
            break;

        case "crcCd":
            scwin.f_sellingAmtFcrc_freight(Row, Colid, olddata);
            scwin.f_sellingAmt_freight(Row, Colid, olddata);
            scwin.f_sellingVat_freight(Row, Colid, olddata);
            scwin.f_sellingUsdAmt_freight(Row, Colid, olddata);
            break;

        case "chgWt":
            scwin.f_sellingAmtFcrc_freight(Row, Colid, olddata);
            scwin.f_sellingAmt_freight(Row, Colid, olddata);
            scwin.f_sellingVat_freight(Row, Colid, olddata);
            scwin.f_sellingUsdAmt_freight(Row, Colid, olddata);
            break;

        case "sellUpr":
            scwin.f_sellingAmtFcrc_freight(Row, Colid, olddata);
            scwin.f_sellingAmt_freight(Row, Colid, olddata);
            scwin.f_sellingVat_freight(Row, Colid, olddata);
            scwin.f_sellingUsdAmt_freight(Row, Colid, olddata);
            break;

        case "exRate":
            scwin.f_sellingAmt_freight(Row, Colid, olddata);
            break;

        case "sellAmt":
            scwin.f_sellingVat_freight(Row, Colid, olddata);
            break;

        case "vatAmt":
            scwin.f_sellingUsdAmt_freight(Row, Colid, olddata);
            break;

        default:
            break;
    }
};

