scwin.gr_ocElList_onviewchange = function (info) {
    if(info.colId == "pgb") {
        if(info.newValue == "Y") {
            gr_ocElList.setCellReadOnly(info.rowIndex, "pseq", false);
            ds_ocElList.setCellData(info.rowIndex, "pseq", "0");
        } else {
            gr_ocElList.setCellReadOnly(info.rowIndex, "pseq", true);
            ds_ocElList.setCellData(info.rowIndex, "pseq", "");
        }
    }
};
